/**
 * Updated-On: 2026-03-03
 * Updated-By: Codex
 * PM-Ticket: UNTRACKED
 *
 * Job runner extraction from autocode_scheduler.js
 * Exposes dispatch/resolve runner methods that can be attached to AutocodeScheduler.
 */

const { enrichTicket } = require('./context_enricher');

function attachJobRunners(AutocodeScheduler) {
  if (!AutocodeScheduler || !AutocodeScheduler.prototype) {
    throw new Error('AutocodeScheduler_class_required');
  }

  AutocodeScheduler.prototype.buildTask = async function buildTask(ticket) {
    const enriched = await enrichTicket(ticket);
    const poolKey = this.inferPoolKey(ticket, enriched);
    return { enriched, poolKey, taskText: enriched.prompt };
  };

  AutocodeScheduler.prototype.dispatchTicket = async function dispatchTicket(ticket, pendingByModel, laneRows, recentDispatchesByModel = null) {
    const ticketId = Number(ticket.ticket_id);
    if (!Number.isFinite(ticketId) || ticketId <= 0) return { dispatched: false, reason: 'invalid_ticket_id' };

    if (String(ticket.ticket_type || '').toLowerCase() === 'improvement') {
      const HIGH_RISK = ['schema', 'migration', 'router', 'deployment', 'database', 'core router', 'db schema'];
      const searchText = `${ticket.title || ''} ${ticket.brief_md || ''} ${(ticket.tags || []).join(' ')}`.toLowerCase();
      const riskMatch = HIGH_RISK.find((term) => searchText.includes(term));
      if (riskMatch) {
        await this.db.query(`
          UPDATE pm_tickets_core
          SET state = 'needs_human', updated_at = NOW()
          WHERE ticket_id = $1
            AND LOWER(COALESCE(state, '')) NOT IN ('needs_human', 'done', 'closed', 'rejected')
        `, [ticketId]).catch(() => {});
        await this.db.query(`
          INSERT INTO pm_events_core (ticket_id, event_type, prev_state, new_state, actor, payload, created_at)
          VALUES ($1, 'autocode.improvement.blocked', $2, 'needs_human', 'autocode_scheduler', $3::jsonb, NOW())
        `, [ticketId, ticket.state || null, JSON.stringify({ reason: 'high_risk_component', matched_term: riskMatch })]).catch(() => {});
        return { dispatched: false, reason: 'improvement_flagged_needs_human', matched_term: riskMatch };
      }
    }

    const { enriched, poolKey, taskText } = await this.buildTask(ticket);
    if (this.requireContextEnrichment && !enriched?.enriched) {
      await this.db.query(`
        INSERT INTO pm_events_core (ticket_id, event_type, prev_state, new_state, actor, payload, created_at)
        VALUES ($1, 'autocode.skipped.missing_context', $2, $2, 'autocode_scheduler', $3::jsonb, NOW())
      `, [
        ticketId,
        ticket.state || null,
        JSON.stringify({
          reason: 'context_enrichment_required',
          file_path: enriched?.file_path || null,
          enrich_reason: enriched?.reason || null
        })
      ]).catch(() => {});
      return { dispatched: false, reason: 'context_required_not_enriched' };
    }

    const target = await this.chooseModel(ticket, poolKey, pendingByModel, laneRows, recentDispatchesByModel);
    if (!target) return { dispatched: false, reason: 'no_allowed_target' };

    const lane = {
      modelKey: target.model,
      workerTarget: target.workerTarget,
      executionRoute: target.executionRoute,
      slotKey: target.slotKey
    };

    if (await this.hasPendingTask(ticketId, lane.modelKey)) return { dispatched: false, reason: 'pending_task_exists' };

    let finalTaskText = taskText;
    const codednaPlan = await this.buildCodeDNAAttachPlan(ticket, lane, Number(process.env.AUTOCODE_CODEDNA_PLAN_LIMIT || '8'));
    if (codednaPlan.length) {
      const planText = this.formatCodeDNAPlan(codednaPlan);
      finalTaskText = `${taskText}\n\n${planText}\n\nUse these primitives first, then fill only missing glue code.`;
    }

    const eventInsert = await this.db.query(`
      INSERT INTO events (kind, ticket_id, user_id, content, metadata, created_at)
      VALUES ('counsel.task', $1, $2, $3, $4::jsonb, NOW())
      RETURNING id
    `, [
      String(ticketId),
      'api:autocode_scheduler',
      finalTaskText,
      JSON.stringify({
        source: 'autocode_scheduler',
        target: lane.modelKey,
        execution_route: lane.executionRoute,
        score_model_key: lane.modelKey,
        slot_key: lane.slotKey,
        auto_dispatch: true,
        workflow_stage: 'autocode',
        task_type: 'autocode',
        pool_key: poolKey,
        ticket_title: ticket.title || '',
        enriched: !!enriched.enriched,
        file_path: enriched.file_path || null,
        file_bytes: Number(enriched.file_bytes || 0),
        enrich_reason: enriched.reason || null,
        codedna_plan_count: codednaPlan.length,
        codedna_primitive_ids: codednaPlan.map((p) => p.primitive_id),
        codedna_librarian_agent: this.codeDNALibrarianAgent,
        dispatch_at: new Date().toISOString()
      })
    ]);
    const eventId = eventInsert.rows[0]?.id || null;

    const logInsert = await this.db.query(`
      INSERT INTO autocode_dispatch_log (ticket_id, slot_key, target_model, worker_target, execution_route, pool_key, event_id, source, created_at)
      VALUES ($1, $2, $3, $4, $5, $6, $7, 'autocode_scheduler', NOW())
      RETURNING id
    `, [ticketId, lane.slotKey, lane.modelKey, lane.workerTarget, lane.executionRoute, poolKey, eventId]);
    const dispatchId = Number(logInsert.rows[0]?.id || 0);

    if (eventId) {
      await this.db.query(`
        UPDATE events
        SET metadata = COALESCE(metadata, '{}'::jsonb) || $2::jsonb
        WHERE id = $1
      `, [eventId, JSON.stringify({ autocode_event_id: Number(eventId), dispatch_id: dispatchId })]).catch(() => {});
    }

    await this.db.query(`
      UPDATE pm_tickets_core
      SET state = CASE WHEN LOWER(COALESCE(state, '')) IN ('todo', 'open') THEN 'in_progress' ELSE state END,
          assigned_model = $2,
          updated_at = NOW()
      WHERE ticket_id = $1
    `, [ticketId, lane.modelKey]);

    await this.db.query(`
      INSERT INTO pm_events_core (ticket_id, event_type, prev_state, new_state, actor, payload, created_at)
      VALUES ($1, 'autocode.dispatched', $2, 'in_progress', 'autocode_scheduler', $3::jsonb, NOW())
    `, [ticketId, ticket.state || null, JSON.stringify({
      event_id: eventId,
      dispatch_id: dispatchId,
      slot_key: lane.slotKey,
      target_model: lane.modelKey,
      worker_target: lane.workerTarget,
      execution_route: lane.executionRoute,
      pool_key: poolKey
    })]).catch(() => {});

    pendingByModel.set(lane.modelKey, (pendingByModel.get(lane.modelKey) || 0) + 1);
    if (recentDispatchesByModel instanceof Map) {
      recentDispatchesByModel.set(lane.modelKey, (recentDispatchesByModel.get(lane.modelKey) || 0) + 1);
    }

    return {
      dispatched: true,
      eventId,
      slotKey: lane.slotKey,
      targetModel: lane.modelKey,
      workerTarget: lane.workerTarget,
      executionRoute: lane.executionRoute,
      poolKey
    };
  };

  AutocodeScheduler.prototype.resolveDispatchOutcomes = async function resolveDispatchOutcomes(limit = 40) {
    const unresolved = await this.db.query(`
      SELECT id, ticket_id, slot_key, target_model, worker_target, execution_route, pool_key, event_id, created_at
      FROM autocode_dispatch_log
      WHERE resolved_at IS NULL
      ORDER BY created_at ASC
      LIMIT $1
    `, [limit]);

    let resolved = 0;
    for (const row of unresolved.rows || []) {
      const ageSec = Math.max(0, Math.floor((Date.now() - new Date(row.created_at).getTime()) / 1000));
      const workerTarget = String(row.worker_target || row.target_model || '').toLowerCase();
      const report = await this.db.query(`
        SELECT id, content, metadata, created_at
        FROM events
        WHERE kind = 'counsel.report'
          AND ticket_id = $1
          AND created_at >= $2
          AND (
            LOWER(COALESCE(metadata->>'target','')) = $3
            OR LOWER(COALESCE(metadata->>'worker','')) = $3
            OR LOWER(COALESCE(metadata->>'model','')) LIKE '%' || $3 || '%'
          )
          AND (
            ($4::bigint IS NOT NULL AND (
              (
                COALESCE(metadata->>'source_event_id','') ~ '^[0-9]+$'
                AND (metadata->>'source_event_id')::bigint = $4
              )
              OR (
                COALESCE(metadata->>'autocode_event_id','') ~ '^[0-9]+$'
                AND (metadata->>'autocode_event_id')::bigint = $4
              )
            ))
            OR (
              $4::bigint IS NULL
              AND COALESCE(NULLIF(metadata->>'workflow_stage',''), 'autocode') = 'autocode'
            )
          )
        ORDER BY created_at ASC
        LIMIT 1
      `, [String(row.ticket_id), row.created_at, workerTarget, row.event_id ? Number(row.event_id) : null]);

      let outcome = null;
      if (report.rows.length > 0) {
        outcome = this.parseOutcomeFromReport(report.rows[0], this.timeoutSeconds);
      } else if (ageSec >= this.timeoutSeconds) {
        outcome = {
          success: false,
          durationMs: this.timeoutSeconds * 1000,
          timeoutSeconds: this.timeoutSeconds,
          errorType: 'timeout',
          errorText: `dispatch_timeout_${this.timeoutSeconds}s_no_report`
        };
      }
      if (!outcome) continue;

      await this.db.query(`
        UPDATE autocode_dispatch_log
        SET success = $2,
            duration_ms = $3,
            error_type = $4,
            resolved_model = COALESCE($5, resolved_model),
            execution_route = COALESCE($6, execution_route),
            completion_mark = $7,
            resolved_at = NOW()
        WHERE id = $1
      `, [row.id, outcome.success, outcome.durationMs, outcome.errorType, outcome.resolvedModel, outcome.executionRoute, !!outcome.ticketComplete]);

      await this.applyPoolScore({
        poolKey: row.pool_key || 'prime/general',
        slotKey: row.slot_key || 'default',
        model: String(row.target_model || '').toLowerCase(),
        success: outcome.success,
        durationMs: outcome.durationMs,
        timeoutSeconds: outcome.timeoutSeconds,
        errorText: outcome.errorText
      });

      if (outcome.success) {
        await this.recordModelSuccess(String(row.target_model || '').toLowerCase());
      }

      await this.enforceFailurePolicy(
        row.pool_key || 'prime/general',
        String(row.target_model || '').toLowerCase(),
        outcome
      );

      await this.recordCodeDNAUsage(row, outcome);

      if (outcome.success) {
        const promoteToReview = this.requireCompletionSignal ? outcome.ticketComplete === true : true;
        await this.db.query(`
          UPDATE pm_tickets_core
          SET state = CASE
                WHEN LOWER(COALESCE(state,'')) = 'in_progress' AND $2::boolean = TRUE THEN 'review'
                WHEN LOWER(COALESCE(state,'')) = 'in_progress' AND $2::boolean = FALSE THEN 'in_progress'
                ELSE state
              END,
              updated_at = NOW()
          WHERE ticket_id = $1
        `, [row.ticket_id, promoteToReview]).catch(() => {});

        await this.db.query(`
          INSERT INTO pm_events_core (ticket_id, event_type, prev_state, new_state, actor, payload, created_at)
          VALUES ($1, $2, 'in_progress', $3, 'autocode_scheduler', $4::jsonb, NOW())
        `, [
          row.ticket_id,
          promoteToReview ? 'autocode.completed' : 'autocode.step_completed',
          promoteToReview ? 'review' : 'in_progress',
          JSON.stringify({
            dispatch_id: row.id,
            slot_key: String(row.slot_key || 'default').toLowerCase(),
            target_model: String(row.target_model || '').toLowerCase(),
            worker_target: String(row.worker_target || '').toLowerCase(),
            execution_route: outcome.executionRoute || row.execution_route || null,
            resolved_model: outcome.resolvedModel || null,
            pool_key: row.pool_key || 'prime/general',
            duration_ms: outcome.durationMs || 0,
            completion_signal: outcome.ticketComplete === true,
            needs_more_work: !promoteToReview
          })
        ]).catch(() => {});
        await this.reconcileHierarchy(row.ticket_id);
      } else {
        await this.db.query(`
          UPDATE pm_tickets_core
          SET state = 'open',
              updated_at = NOW()
          WHERE ticket_id = $1
        `, [row.ticket_id]).catch(() => {});
        await this.db.query(`
          INSERT INTO pm_events_core (ticket_id, event_type, prev_state, new_state, actor, payload, created_at)
          VALUES ($1, 'autocode.failed', 'in_progress', 'open', 'autocode_scheduler', $2::jsonb, NOW())
        `, [row.ticket_id, JSON.stringify({
          dispatch_id: row.id,
          slot_key: String(row.slot_key || 'default').toLowerCase(),
          target_model: String(row.target_model || '').toLowerCase(),
          worker_target: String(row.worker_target || '').toLowerCase(),
          execution_route: outcome.executionRoute || row.execution_route || null,
          resolved_model: outcome.resolvedModel || null,
          pool_key: row.pool_key || 'prime/general',
          error_type: outcome.errorType || 'failed',
          error: outcome.errorText || null
        })]).catch(() => {});
        await this.reconcileHierarchy(row.ticket_id);
      }

      resolved += 1;
    }

    this.stats.resolved_total += resolved;
    this.stats.last_resolved = resolved;
    return resolved;
  };
}

module.exports = {
  attachJobRunners
};
