/**
 * Updated-On: 2026-03-03
 * Updated-By: Codex
 * PM-Ticket: UNTRACKED
 *
 * Routes extracted from autocode_scheduler.js
 */

const express = require('express');

function buildAutocodeSchedulerRoutes(scheduler) {
  const router = express.Router();

  router.get('/status', async (_req, res) => {
    res.json({ success: true, scheduler: scheduler.status() });
  });

  router.get('/pools', async (req, res) => {
    const limit = Math.max(1, Math.min(500, parseInt(req.query?.limit || '200', 10)));
    const rows = await scheduler.getPoolLeaderboard(limit);
    res.json({ success: true, rows });
  });

  router.get('/runs', async (req, res) => {
    const limit = Math.max(1, Math.min(1000, parseInt(req.query?.limit || '200', 10)));
    const rows = await scheduler.getRecentRuns(limit);
    res.json({ success: true, rows });
  });

  router.get('/active', async (req, res) => {
    const limit = Math.max(1, Math.min(1000, parseInt(req.query?.limit || '200', 10)));
    const active = await scheduler.getActiveRuns(limit);
    res.json({ success: true, ...active, scheduler: scheduler.status() });
  });

  router.get('/blocked/report', async (req, res) => {
    const limit = Math.max(1, Math.min(200, parseInt(req.query?.limit || '50', 10)));
    const report = await scheduler.getBlockedReport(limit);
    res.json({ success: true, ...report, scheduler: scheduler.status() });
  });

  router.get('/fairness', async (req, res) => {
    const limit = Math.max(1, Math.min(500, parseInt(req.query?.limit || '100', 10)));
    const report = await scheduler.getFairnessReport(limit);
    res.json({ success: true, ...report, scheduler: scheduler.status() });
  });

  router.get('/circuit-breaker', async (_req, res) => {
    const suspended = await scheduler.getSuspendedModelsReport();
    res.json({ success: true, suspended_count: suspended.length, suspended, scheduler: scheduler.status() });
  });

  router.post('/circuit-breaker/:model/unsuspend', async (req, res) => {
    const model = String(req.params?.model || '').trim().toLowerCase();
    if (!model) return res.status(400).json({ success: false, error: 'model_required' });
    const actor = String(req.body?.actor || 'itouch').trim() || 'itouch';
    const row = await scheduler.unsuspendModel(model, actor);
    if (!row) return res.status(404).json({ success: false, error: 'model_not_suspended_or_not_found', model });
    res.json({ success: true, model, row, scheduler: scheduler.status() });
  });

  router.get('/slots', async (req, res) => {
    const includeDisabled = String(req.query?.include_disabled || 'false').toLowerCase() === 'true';
    const slots = await scheduler.getSlotLanes(includeDisabled);
    res.json({ success: true, slots, scheduler: scheduler.status() });
  });

  router.post('/slots', async (req, res) => {
    try {
      const slot = await scheduler.upsertSlotLane(req.body || {});
      res.json({ success: true, slot });
    } catch (err) {
      res.status(400).json({ success: false, error: err.message });
    }
  });

  router.post('/assign-lane', async (req, res) => {
    try {
      const ticketId = Number(req.body?.ticket_id || 0);
      const slotKey = String(req.body?.slot_key || '').trim().toLowerCase();
      if (!(ticketId > 0)) return res.status(400).json({ success: false, error: 'valid_ticket_id_required' });
      if (!slotKey) return res.status(400).json({ success: false, error: 'slot_key_required' });

      const lanes = await scheduler.getSlotLanes(true);
      const lane = lanes.find((r) => String(r.slot_key || '').toLowerCase() === slotKey);
      if (!lane) return res.status(404).json({ success: false, error: 'slot_not_found' });

      const laneTag = `lane:${slotKey}`;
      const markAutocodeReady = req.body?.autocode_ready !== false;
      const readyTag = 'autocode-ready';

      await scheduler.db.query(`
        UPDATE pm_tickets_core
        SET tags = ARRAY(
              SELECT DISTINCT t
              FROM unnest(
                COALESCE(pm_tickets_core.tags, ARRAY[]::text[])
                || ARRAY[$2]::text[]
