    { name: 'recent_activity', ok: (recentReports.length + recentBridge.length) > 0, details: { reports: recentReports.length, bridge_runs: recentBridge.length } },
    { name: 'evidence_of_work', ok: completedBridge.length > 0 || recentReports.length > 0, details: { bridge_completed_or_dry_run: completedBridge.length, reports: recentReports.length } }
  ];
  const pass = checks.every((c) => c.ok);
  const summary = {
    pass,
    checks,
    evidence,
    lookback_hours: safeLookbackHours,
    ticket: {
      ticket_id: ticket.ticket_id,
      state: ticket.state,
      title: ticket.title,
      assigned_model: ticket.assigned_model,
      source_story_id: ticket.source_story_id
    },
    recommended_actions: pass
      ? ['May transition to done (subject to human review and approval).']
      : ['Inspect ticket events and counsel.report output', 'Run bridge.diff / bridge.patch dry_run and retry verification']
  };

  await db.query(`
    INSERT INTO pm_events_core (ticket_id, event_type, prev_state, new_state, actor, payload, created_at)
    VALUES ($1, 'qa.verify_claims', NULL, NULL, $2, $3::jsonb, NOW())
  `, [ticketId, actor, JSON.stringify(summary)]).catch(() => {});

  return { success: true, ...summary };
}

