  const q = await db.query(`
    SELECT project_id
    FROM pm_projects_simple
    WHERE lower(name) = lower($1)
    LIMIT 1
  `, [n]);
  if (q.rows.length) return Number(q.rows[0].project_id);
  const ins = await db.query(`
    INSERT INTO pm_projects_simple (name, description, status, created_at, updated_at)
    VALUES ($1, $2, 'active', NOW(), NOW())
    RETURNING project_id
  `, [n, asText(description) || \`Canonical PM project for \${n}\`]);
