async function resolveTicketId(db, anyId) {
  const id = toInt(anyId, null);
  if (!id || id <= 0) return null;
  const direct = await db.query(`
    SELECT ticket_id
    FROM pm_tickets_core
    WHERE ticket_id = $1
    LIMIT 1
  `, [id]);
  if (direct.rows.length) return Number(direct.rows[0].ticket_id);
  const viaStory = await db.query(`
    SELECT ticket_id
    FROM pm_tickets_core
    WHERE source_story_id = $1
    ORDER BY ticket_id DESC
    LIMIT 1
  `, [id]);
  if (viaStory.rows.length) return Number(viaStory.rows[0].ticket_id);
  return null;
}

async function resolveStoryId(db, anyId) {
  const id = toInt(anyId, null);
  if (!id || id <= 0) return null;
  const direct = await db.query(`
    SELECT story_id
    FROM pm_stories_simple
    WHERE story_id = $1
    LIMIT 1
  `, [id]);
  if (direct.rows.length) return Number(direct.rows[0].story_id);

  const viaTicket = await db.query(`
    SELECT source_story_id
    FROM pm_tickets_core
    WHERE ticket_id = $1
    LIMIT 1
  `, [id]);
  const storyId = Number(viaTicket.rows[0]?.source_story_id || 0);
  if (storyId > 0) return storyId;

  const viaLink = await db.query(`
    SELECT story_id
    FROM pm_story_ticket_links
    WHERE ticket_id = $1
    LIMIT 1
  `, [id]).catch(() => ({ rows: [] }));
  const linkedStoryId = Number(viaLink.rows[0]?.story_id || 0);
  return linkedStoryId > 0 ? linkedStoryId : null;
}

async function linkStoryTicket(db, storyId, ticketId, relationType, sortOrder) {
  await db.query(`
    INSERT INTO pm_story_ticket_links (story_id, ticket_id, relation_type, sort_order, created_at)
    VALUES ($1, $2, $3, $4, NOW())
    ON CONFLICT (ticket_id)
    DO UPDATE SET
      story_id = EXCLUDED.story_id,
      relation_type = EXCLUDED.relation_type,
      sort_order = EXCLUDED.sort_order
  `, [storyId, ticketId, relationType, sortOrder]);
}

function parseSubticketSpecs(raw) {
  if (!Array.isArray(raw)) return [];
  return raw
    .map((x, idx) => ({
      title: asText(x?.title || x?.name || '').slice(0, 240),
      brief_md: asText(x?.description || x?.brief_md || '').slice(0, 12000),
      state: asText(x?.state || 'todo').toLowerCase(),
      priority: toInt(x?.priority, 2),
      assigned_model: asText(x?.assigned_model || '') || null,
      tags: Array.isArray(x?.tags) ? x.tags.map((t) => asText(t)).filter(Boolean) : [],
      sort_order: toInt(x?.sort_order, idx + 1)
    }))
    .filter((x) => x.title);
}

async function createChildTicket(db, base, spec, storyId, actor) {
  const childTags = Array.from(new Set([
    ...base.tags,
    ...spec.tags,
    'autocode-ready',
    \`parent-story:\${storyId}\`,
    'story-child'
  ]));
  const ins = await db.query(`
    INSERT INTO pm_tickets_core
    (source_story_id, project_id, epic_id, title, brief_md, ticket_type, owner, assigned_model, state, priority, tags, version, created_at, updated_at)
    VALUES (NULL, $1, $2, $3, $4, 'subtask', $5, $6, $7, $8, $9::text[], 1, NOW(), NOW())
    RETURNING ticket_id, title, state, project_id, epic_id
  `, [
    base.project_id,
    base.epic_id,
    spec.title,
    spec.brief_md || spec.title,
    actor,
    spec.assigned_model || base.assigned_model,
    spec.state || 'todo',
    spec.priority || base.priority || 2,
    childTags
  ]);
  return ins.rows[0];
}

