router.post('/story', async (req, res) => {
  const db = req.app.locals.dbClient;
  if (!db) return res.status(500).json({ success: false, error: 'db_unavailable' });
  try {
    await ensureStoryTicketLinksTable(db);
    const projectName = asText(req.body?.project_name || 'Alfred General');
    const epicName = asText(req.body?.epic_name || 'General');
    const title = asText(req.body?.title || req.body?.name || '');
    const description = asText(req.body?.description || req.body?.brief_md || '');
    if (!title) return res.status(400).json({ success: false, error: 'title_required' });

    const owner = asText(req.body?.owner || 'alfred');
    const assignedModel = asText(req.body?.assigned_model || '') || null;
    const state = asText(req.body?.state || 'todo').toLowerCase();
    const priority = toInt(req.body?.priority, 2);
    const inputTags = Array.isArray(req.body?.tags) ? req.body.tags.map((t) => asText(t)).filter(Boolean) : [];
    const childSpecs = parseSubticketSpecs(req.body?.subtickets);
    const tags = childSpecs.length > 0
      ? Array.from(new Set(inputTags.filter((t) => t.toLowerCase() !== 'autocode-ready').concat(['story-root'])))
      : inputTags;

    const projectId = await ensureProject(db, projectName, req.body?.project_description);
    const epicId = await ensureEpic(db, projectId, epicName, req.body?.epic_description);

    const story = await db.query(`
      INSERT INTO pm_stories_simple
      (epic_id, title, description, status, priority, story_points, owner, assignee, created_at, updated_at, tags)
      VALUES ($1, $2, $3, $4, $5, 2, $6, $7, NOW(), NOW(), $8::text[])
      RETURNING story_id
    `, [epicId, title, description, state, priority, owner, assignedModel, tags]);
    const storyId = Number(story.rows[0].story_id);

    // pm_stories_simple INSERT may auto-create a linked pm_tickets_core row via trigger.
    // Use that canonical ticket if present; otherwise create one as fallback.
    const linked = await db.query(`
      SELECT ticket_id, state, project_id, epic_id, source_story_id
      FROM pm_tickets_core
      WHERE source_story_id = $1
      ORDER BY ticket_id DESC
      LIMIT 1
    `, [storyId]);

    let ticketRow = linked.rows[0] || null;
    if (ticketRow) {
      await db.query(`
        UPDATE pm_tickets_core
        SET project_id = $2,
            epic_id = $3,
            title = $4,
            brief_md = $5,
            ticket_type = 'task',
            owner = $6,
            assigned_model = $7,
            state = $8,
            priority = $9,
            tags = $10::text[],
            updated_at = NOW()
        WHERE ticket_id = $1
      `, [ticketRow.ticket_id, projectId, epicId, title, description, owner, assignedModel, state, priority, tags]);
      const refreshed = await db.query(`
        SELECT ticket_id, title, state, project_id, epic_id, source_story_id
        FROM pm_tickets_core
        WHERE ticket_id = $1
      `, [ticketRow.ticket_id]);
      ticketRow = refreshed.rows[0];
    } else {
      const fallback = await db.query(`
        INSERT INTO pm_tickets_core
        (source_story_id, project_id, epic_id, title, brief_md, ticket_type, owner, assigned_model, state, priority, tags, version, created_at, updated_at)
        VALUES ($1, $2, $3, $4, $5, 'task', $6, $7, $8, $9, $10::text[], 1, NOW(), NOW())
        RETURNING ticket_id, title, state, project_id, epic_id, source_story_id
      `, [storyId, projectId, epicId, title, description, owner, assignedModel, state, priority, tags]);
      ticketRow = fallback.rows[0];
    }

    await db.query(`
      INSERT INTO pm_events_core (ticket_id, event_type, prev_state, new_state, actor, payload, created_at)
      VALUES ($1, 'canonical.story.created', NULL, $2, $3, $4::jsonb, NOW())
    `, [ticketRow.ticket_id, ticketRow.state, owner, JSON.stringify({ story_id: storyId, project_name: projectName, epic_name: epicName })]).catch(() => {});

    await linkStoryTicket(db, storyId, Number(ticketRow.ticket_id), 'root', 0);

    const createdChildren = [];
    for (const spec of childSpecs) {
      const child = await createChildTicket(db, {
        project_id: Number(ticketRow.project_id),
        epic_id: Number(ticketRow.epic_id),
        assigned_model: assignedModel,
        priority,
        tags
      }, spec, storyId, owner);
      await linkStoryTicket(db, storyId, Number(child.ticket_id), 'child', spec.sort_order);
      createdChildren.push({
        ticket_id: Number(child.ticket_id),
        title: child.title,
        state: child.state,
        sort_order: spec.sort_order
      });
      await db.query(`
        INSERT INTO pm_events_core (ticket_id, event_type, prev_state, new_state, actor, payload, created_at)
        VALUES ($1, 'canonical.story.child_ticket.created', NULL, $2, $3, $4::jsonb, NOW())
      `, [
        Number(child.ticket_id),
        child.state,
        owner,
        JSON.stringify({ story_id: storyId, parent_ticket_id: Number(ticketRow.ticket_id), sort_order: spec.sort_order })
      ]).catch(() => {});
    }

    return res.json({
      success: true,
      ticket_id: Number(ticketRow.ticket_id),
      story_id: storyId,
      state: ticketRow.state,
      project_id: Number(ticketRow.project_id),
      epic_id: Number(ticketRow.epic_id),
      subtickets_created: createdChildren.length,
      subtickets: createdChildren
    });
  } catch (err) {
    return res.status(500).json({ success: false, error: err.message });
  }
});

router.patch('/story/:id', async (req, res) => {
  const db = req.app.locals.dbClient;
  if (!db) return res.status(500).json({ success: false, error: 'db_unavailable' });
  try {
    const ticketId = await resolveTicketId(db, req.params.id);
    if (!ticketId) return res.status(404).json({ success: false, error: 'ticket_not_found' });
    const patch = {
      title: req.body?.title ?? null,
      brief_md: req.body?.description ?? req.body?.brief_md ?? null,
      state: req.body?.state ?? null,
      priority: req.body?.priority ?? null,
      assigned_model: req.body?.assigned_model ?? null,
      tags: Array.isArray(req.body?.tags) ? req.body.tags : null
    };
    await db.query(`
      UPDATE pm_tickets_core
      SET title = COALESCE($2, title),
          brief_md = COALESCE($3, brief_md),
          state = COALESCE($4, state),
          priority = COALESCE($5, priority),
          assigned_model = COALESCE($6, assigned_model),
          tags = COALESCE($7, tags),
          updated_at = NOW()
      WHERE ticket_id = $1
    `, [ticketId, patch.title, patch.brief_md, patch.state, patch.priority, patch.assigned_model, patch.tags]);
    const row = await db.query(`SELECT ticket_id, source_story_id, state FROM pm_tickets_core WHERE ticket_id = $1`, [ticketId]);

    if (row.rows[0]?.source_story_id) {
      await db.query(`
        UPDATE pm_stories_simple
        SET title = COALESCE($2, title),
            description = COALESCE($3, description),
            status = COALESCE($4, status),
            priority = COALESCE($5, priority),
            tags = COALESCE($6, tags),
            updated_at = NOW()
        WHERE story_id = $1
      `, [row.rows[0].source_story_id, patch.title, patch.brief_md, patch.state, patch.priority, patch.tags]).catch(() => {});
    }
    return res.json({ success: true, ticket_id: Number(row.rows[0].ticket_id), state: row.rows[0].state });
  } catch (err) {
    return res.status(500).json({ success: false, error: err.message });
  }
});

