router.post('/story/:id/tickets', async (req, res) => {
  const db = req.app.locals.dbClient;
  if (!db) return res.status(500).json({ success: false, error: 'db_unavailable' });
  try {
    await ensureStoryTicketLinksTable(db);
    const storyId = await resolveStoryId(db, req.params.id);
    if (!storyId) return res.status(404).json({ success: false, error: 'story_not_found' });
    const actor = asText(req.body?.actor || 'canonical-pm');
    const storyMeta = await db.query(`
      SELECT
        s.story_id,
        coalesce(s.priority, 2) AS story_priority,
        coalesce(s.tags, ARRAY[]::text[]) AS story_tags,
        t.ticket_id AS root_ticket_id,
        t.project_id,
        t.epic_id,
        t.assigned_model
      FROM pm_stories_simple s
      LEFT JOIN pm_tickets_core t ON t.source_story_id = s.story_id
      WHERE s.story_id = $1
      ORDER BY t.ticket_id ASC
      LIMIT 1
    `, [storyId]);
    const base = storyMeta.rows[0];
    if (!base?.project_id || !base?.epic_id) {
      return res.status(400).json({ success: false, error: 'story_scope_unresolved' });
    }

    const specs = parseSubticketSpecs(req.body?.subtickets);
    if (!specs.length) return res.status(400).json({ success: false, error: 'subtickets_required' });

    const created = [];
    for (const spec of specs) {
      const child = await createChildTicket(db, {
        project_id: Number(base.project_id),
        epic_id: Number(base.epic_id),
        assigned_model: base.assigned_model,
        priority: Number(base.story_priority || 2),
        tags: Array.isArray(base.story_tags) ? base.story_tags : []
      }, spec, storyId, actor);
      await linkStoryTicket(db, storyId, Number(child.ticket_id), 'child', spec.sort_order);
      created.push({
        ticket_id: Number(child.ticket_id),
        title: child.title,
        state: child.state,
        sort_order: spec.sort_order
      });
      await db.query(`
        INSERT INTO pm_events_core (ticket_id, event_type, prev_state, new_state, actor, payload, created_at)
        VALUES ($1, 'canonical.story.child_ticket.created', NULL, $2, $3, $4::jsonb, NOW())
      `, [
        Number(child.ticket_id),
        child.state,
        actor,
        JSON.stringify({ story_id: storyId, parent_ticket_id: Number(base.root_ticket_id || 0), sort_order: spec.sort_order })
      ]).catch(() => {});
    }

    return res.json({
      success: true,
      story_id: storyId,
      created_count: created.length,
      tickets: created
    });
  } catch (err) {
    return res.status(500).json({ success: false, error: err.message });
  }
});

module.exports = router;
