router.post('/ticket/:id/status', async (req, res) => {
  const db = req.app.locals.dbClient;
  if (!db) return res.status(500).json({ success: false, error: 'db_unavailable' });
  try {
    const ticketId = await resolveTicketId(db, req.params.id);
    if (!ticketId) return res.status(404).json({ success: false, error: 'ticket_not_found' });
    const state = asText(req.body?.state || req.body?.status || '').toLowerCase();
    if (!state) return res.status(400).json({ success: false, error: 'state_required' });
    const actor = asText(req.body?.actor || 'canonical-pm');

    const prev = await db.query(`
      SELECT source_story_id, state
      FROM pm_tickets_core
      WHERE ticket_id = $1
      LIMIT 1
    `, [ticketId]);
    const prevState = prev.rows[0]?.state || null;
    const sourceStoryId = Number(prev.rows[0]?.source_story_id || 0) || null;

    const requireVerifyForDone = true; // hard default for safety; bypass must be explicit and audited
    const allowUnverifiedDone = truthy(req.body?.allow_unverified_done) || truthy(req.body?.force);
    const allowFullAutonomy = String(process.env.ALLOW_FULL_AUTONOMY || 'false').trim().toLowerCase() === 'true';
    if (state === 'done' && requireVerifyForDone && !allowUnverifiedDone) {
      if (req.body?.auto_verify_claims !== false) {
        await runQaVerifyClaimsForTicket(db, ticketId, {
          actor: \`\${actor || 'canonical-pm'}.auto_verify\`,
          lookbackHours: toInt(req.body?.qa_lookback_hours, 72) || 72
        }).catch(() => null);
      }
      const qa = await db.query(`
        SELECT event_id, payload, created_at
        FROM pm_events_core
        WHERE ticket_id = $1
          AND event_type = 'qa.verify_claims'
        ORDER BY created_at DESC, event_id DESC
        LIMIT 1
      `, [ticketId]).catch(() => ({ rows: [] }));
      const qaRow = qa.rows?.[0] || null;
      const qaPayload = qaRow?.payload && typeof qaRow.payload === 'object' ? qaRow.payload : {};
      const qaPassed = qaPayload?.pass === true;
      const qaRecentMs = qaRow?.created_at ? (Date.now() - new Date(qaRow.created_at).getTime()) : Number.POSITIVE_INFINITY;
      const qaMaxAgeMs = Math.max(60_000, parseInt(String(process.env.PM_QA_VERIFY_MAX_AGE_MS || '86400000'), 10) || 86400000;
      if (!qaPassed || !Number.isFinite(qaRecentMs) || qaRecentMs > qaMaxAgeMs) {
        return res.status(409).json({
          success: false,
          error: 'qa_verify_required_before_done',
          ticket_id: ticketId,
          state_requested: state,
          hint: 'Run qa.verify_claims for this ticket and retry, or pass allow_unverified_done=true (discouraged)',
          qa_verify: {
            required: true,
            latest_event_id: qaRow?.event_id || null,
            latest_created_at: qaRow?.created_at || null,
            latest_pass: qaPassed === true,
            latest_age_ms: Number.isFinite(qaRecentMs) ? qaRecentMs : null,
            max_age_ms: qaMaxAgeMs
          }
        });
      }
    }
    if (state === 'done' && allowUnverifiedDone) {
      if (!allowFullAutonomy) {
        await db.query(`
          INSERT INTO pm_events_core (ticket_id, event_type, prev_state, new_state, actor, payload, created_at)
          VALUES ($1, 'canonical.ticket.done_bypass_blocked', $2, $3, $4, $5::jsonb, NOW())
        `, [ticketId, prevState, state, actor, JSON.stringify({
          reason: 'ALLOW_FULL_AUTONOMY_disabled',
          allow_unverified_done_requested: true
        })]).catch(() => {});
        return res.status(409).json({
          success: false,
          error: 'full_autonomy_bypass_disabled',
          hint: 'Set ALLOW_FULL_AUTONOMY=true to permit allow_unverified_done, or remove bypass and let qa.verify_claims run'
        });
      }
      await db.query(`
        INSERT INTO pm_events_core (ticket_id, event_type, prev_state, new_state, actor, payload, created_at)
        VALUES ($1, 'canonical.ticket.done_bypass_used', $2, $3, $4, $5::jsonb, NOW())
      `, [ticketId, prevState, state, actor, JSON.stringify({
        reason: 'allow_unverified_done',
        allow_unverified_done_requested: true,
        allow_full_autonomy: true
      })]).catch(() => {});
    }

    await db.query(`
      UPDATE pm_tickets_core
      SET state = $2, updated_at = NOW()
      WHERE ticket_id = $1
    `, [ticketId, state]);

    if (sourceStoryId) {
      await db.query(`
        UPDATE pm_stories_simple
        SET status = $2, updated_at = NOW()
        WHERE story_id = $1
      `, [sourceStoryId, state]).catch(() => {});
    }

    await db.query(`
      INSERT INTO pm_events_core (ticket_id, event_type, prev_state, new_state, actor, payload, created_at)
      VALUES ($1, 'canonical.ticket.status', $2, $3, $4, $5::jsonb, NOW())
    `, [ticketId, prevState, state, actor, JSON.stringify({ source_story_id: sourceStoryId })]).catch(() => {});
    void recordTicketTransition(db, {
      ticket_id: ticketId,
      from_state: prevState,
      to_state: state,
      actor,
      assigned_model: null,
      is_rework: ['in_progress', 'open', 'needs_input'].includes(String(state || '').toLowerCase())
        && ['review', 'testing', 'in_review', 'blocked'].includes(String(prevState || '').toLowerCase()),
      metadata: { source: 'canonical_pm_routes.ticket_status', source_story_id: sourceStoryId || null }
    });

    let releasedLocks = 0;
    if (state === 'done') {
      try {
        await db.query(`
          CREATE TABLE IF NOT EXISTS counsel_bridge_file_locks (
            target_path TEXT PRIMARY KEY,
            active BOOLEAN NOT NULL DEFAULT TRUE,
            lock_scope TEXT NOT NULL DEFAULT 'in_review',
            ticket_id TEXT,
            story_id BIGINT,
            owner_model_id TEXT,
            owner_run_id BIGINT,
            lock_reason TEXT,
            acquired_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            refreshed_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            released_at TIMESTAMPTZ
          )
        `).catch(() => {});
        const unlock = await db.query(`
          UPDATE counsel_bridge_file_locks
          SET active = FALSE,
              released_at = NOW(),
              refreshed_at = NOW()
          WHERE ticket_id = $1
            AND active = TRUE
          RETURNING target_path
        `, [String(ticketId)]);
        releasedLocks = unlock.rows.length;
        if (releasedLocks > 0) {
          await db.query(`
            INSERT INTO pm_events_core (ticket_id, event_type, prev_state, new_state, actor, payload, created_at)
            VALUES ($1, 'canonical.ticket.done.unlock_files', $2, $3, $4, $5::jsonb, NOW())
          `, [ticketId, prevState, state, actor, JSON.stringify({
            released_lock_count: releasedLocks,
            released_paths: unlock.rows.map((r) => r.target_path).filter(Boolean).slice(0, 50)
          })]).catch(() => {});
        }
      } catch (_) {}
    }

    return res.json({ success: true, ticket_id: ticketId, state, prev_state: prevState, source_story_id: sourceStoryId, released_file_locks: releasedLocks });
  } catch (err) {
    return res.status(500).json({ success: false, error: err.message });
  }
});

