```js
// ---- helpers (from codedna) ----
function isTooShort(report) { return report.body.length < 200; }

const TIMEOUT_PHRASES = [
  /timeout of \d+ms exceeded/i,
  /ollama failed/i,
  /tool_execution_failed/i,
];
function hasOnlyTimeout(report) {
  const txt = report.body.trim();
  return TIMEOUT_PHRASES.some(r => r.test(txt)) && txt.split(/\s+/).length <= 5;
}

function isOneLiner(report) {
  const lines = report.body.trim().split('\n');
  const hasCode = /```/.test(report.body);
  return lines.length === 1 && !hasCode;
}

const WORKSPACE_ROOT = process.env.WORKSPACE_ROOT || '/workspace';
function allWriteFilePathsOutside(report) {
  const blocks = report.body.match(/WRITE_FILE\(([^)]+)\)/g) || [];
  return blocks.every(b => {
    const path = b.match(/WRITE_FILE\(([^,]+),/)[1]
                 .trim().replace(/^["']|["']$/g, '');
    return !path.startsWith(WORKSPACE_ROOT);
  });
}

// ---- scoring & logging ----
function computeQualityScore(report) {
  let score = 100;
  if (isTooShort(report))            score -= 30;
  if (hasOnlyTimeout(report))        score -= 30;
  if (isOneLiner(report))            score -= 20;
  if (allWriteFilePathsOutside(report)) score -= 20;
  return Math.max(score, 0);
}
function logQualityEvent(workerId, score, meta = {}) {
  emitEvent({ type: 'quality_score', worker: workerId, score, ...meta });
}

// ---- integration point (before setting state = in_review) ----
const score = computeQualityScore(report);
logQualityEvent(worker.id, score, { reportId: report.id });

if (score < 40) {
  const reason = (() => {
    if (isTooShort(report))            return 'LENGTH_TOO_SHORT';
    if (hasOnlyTimeout(report))        return 'TIMEOUT_PHRASE_ONLY';
    if (isOneLiner(report))            return 'ONE_LINER';
    if (allWriteFilePathsOutside(report)) return 'ALL_WRITE_FILE_OUTSIDE';
    return 'UNKNOWN';
  })();

  emitEvent({
    type: 'repair.needed',
    reason: 'quality_gate_fail',
    content: `QUALITY_GATE_FAIL: ${reason}\n${report.body.slice(0, 500)}`,
    reportId: report.id,
  });
  // bounce – do not move to review
  return;
}

// Normal flow
report.state = 'in_review';
