  return t.toLocaleString() + " tokens";
}

// Build a single bubble
function bubble(role, text) {
  const div = document.createElement('div');
  div.className = `bubble ${role}`;
  const tag = document.createElement('span');
  tag.className = `tag ${role}`;
  tag.textContent = role.charAt(0).toUpperCase() + role.slice(1) + ':';
  div.append(tag, document.createTextNode(' ' + text));
  return div;
}

// Render one run (row from DB)
function renderRun(row) {
  const container = document.createElement('div');
  container.className = 'run';

  // Header – clickable to toggle body
  const header = document.createElement('div');
  header.className = 'run-header';
  header.innerHTML = `
    <span>#${row.ticket_id} – ${row.triggered_by}</span>
    <span class="run-meta">
      ${fmtMs(row.duration_ms)} • ${fmtTokens(row.tokens_used)}
      ${row.alfred_synthesis.includes('[ESCALATE:]') ? '<span class="escalate">Escalated</span>' : ''}
    </span>
  `;
  header.addEventListener('click', () => {
    body.style.display = body.style.display === 'none' ? 'block' : 'none';
  });

  // Body – conversation thread
  const body = document.createElement('div');
  body.className = 'run-body';
  body.style.display = 'none';

  // Order: Alfred initial → Loki → Echo → Alfred synthesis
  body.appendChild(bubble('alfred', row.alfred_initial));
  if (row.loki_response) body.appendChild(bubble('loki', row.loki_response));
  if (row.echo_response) body.appendChild(bubble('echo', row.echo_response));
  body.appendChild(bubble('synth', row.alfred_synthesis));

  container.append(header, body);
  return container;
}

