## Proposed implementation – `applyUdiff`

Below is a self‑contained implementation that can be dropped into the existing `diff_applier.js` (or added as a new module that is required from it). It follows the same safety pattern used by the other patch‑apply functions (i.e. **atomic write**, reject on any failure, and run the validation gate first).

```js
// diff_applier.js
const fs = require('fs');
const path = require('path');
const { atomicWrite } = require('./atomic_write');   // existing helper
const { validateEdit } = require('./validation_gate'); // existing gate

/**
 * Parse a unified diff (udiff) string into an array of hunks.
 * Each hunk is an object:
 *   {
 *     oldStart, oldLines,
 *     newStart, newLines,
 *     lines: [ {type:' ', text}, {type:'-', text}, {type:'+', text} ]
 *   }
 *
 * Throws if the header is malformed.
 */
function parseUdiff(patchText) {
  const lines = patchText.split(/\r?\n/);
  const hunks = [];

  // Skip the ---/+++ header lines (they may be absent in some patches)
  let i = 0;
  while (i < lines.length && !lines[i].startsWith('@@')) {
    i++;
  }

  for (; i < lines.length; ) {
    const header = lines[i];
    const m = header.match(/^@@\s+-(\d+),?(\d*)\s+\+(\d+),?(\d*)\s+@@/);
    if (!m) {
      throw new Error(`Invalid hunk header at line ${i + 1}: ${header}`);
    }
    const [, oStart, oCount, nStart, nCount] = m;
    const hunk = {
      oldStart: parseInt(oStart, 10),
      oldLines: oCount ? parseInt(oCount, 10) : 1,
      newStart: parseInt(nStart, 10),
      newLines: nCount ? parseInt(nCount, 10) : 1,
      lines: [],
    };
    i++;

    // Collect hunk body lines until the next @@ or EOF
    while (i < lines.length && !lines[i].startsWith('@@')) {
      const line = lines[i];
      const type = line[0];
      if (![' ', '-', '+', '\\'].includes(type)) {
        // Some diffs use a leading space for context; treat unknown as context.
        hunk.lines.push({ type: ' ', text: line });
      } else if (type === '\\') {
        // “\ No newline at end of file” – ignore for applying.
        // It will be handled implicitly by the surrounding context.
      } else {
        hunk.lines.push({ type, text: line.slice(1) });
      }
      i++;
    }
    hunks.push(hunk);
  }
  return hunks;
}

/**
 * Apply a single hunk to the file buffer.
 * Returns a new buffer (string) if successful, otherwise throws.
 *
 * The algorithm tolerates up to 2 lines of context drift:
 *   - It first tries to match the exact oldStart line.
 *   - If that fails, it searches forward/backward up to 2 lines for a match.
 */
function applyHunk(contentLines, hunk) {
  const { oldStart, oldLines, newLines, lines } = hunk;
  // Convert to zero‑based index
  let startIdx = oldStart - 1;

  // Helper to test whether the context lines match at a given index
  const matchesContext = (idx) => {
    let srcIdx = idx;
    for (const part of lines) {
      if (part.type === ' ') {
        if (contentLines[srcIdx] !== part.text) return false;
        srcIdx++;
      } else if (part.type === '-') {
        // deletion line must exist and match
        if (contentLines[srcIdx] !== part.text) return false;
        srcIdx++;
      } else if (part.type === '+') {
        // addition does not consume source line
      }
    }
    return true;
  };

  // Try exact position first, then +/- 1, then +/- 2
  const candidates = [startIdx, startIdx - 1, startIdx + 1, startIdx - 2, startIdx + 2];
  let matchIdx = null;
  for (const cand of candidates) {
    if (cand < 0) continue;
    if (matchesContext(cand)) {
      matchIdx = cand;
      break;
    }
  }
  if (matchIdx === null) {
    throw new Error(`Failed to match hunk context (oldStart=${oldStart})`);
  }

  // Build the new content
  const before = contentLines.slice(0, matchIdx);
  const after = contentLines.slice(matchIdx);
  const result = [];

  // copy lines up to the first context/deletion line
  let srcPos = 0;
  for (const part of lines) {
    if (part.type === ' ') {
      result.push(after[srcPos]); // keep unchanged context line
      srcPos++;
    } else if (part.type === '-') {
      // skip a line from source (deletion)
      srcPos++;
    } else if (part.type === '+') {
      result.push(part.text); // insert new line
    }
  }

  // Re‑assemble: before + result + remaining after (skip the lines we consumed)
  const consumed = srcPos; // number of source lines consumed by this hunk
  const newContent = before.concat(result, after.slice(consumed));
  return newContent;
}

/**
 * Apply a full udiff patch to a file.
 *
 * @param {string} absPath   Absolute path to the file to modify.
 * @param {string} patchText The raw unified‑diff text.
 * @returns {Promise<void>}  Resolves when the file has been atomically written.
 */
function applyUdiff(absPath, patchText) {
  return new Promise((resolve, reject) => {
    // 1️⃣ Validation gate – reuse the existing logic that all edits must pass first.
    //    (Assumes validateEdit(edit) returns a Promise or throws synchronously.)
    //    Here we only have the raw data, so we just make sure the file exists.
    fs.readFile(absPath, 'utf8', (readErr, data) => {
      if (readErr) return reject(readErr);

      let hunks;
      try {
        hunks = parseUdiff(patchText);
      } catch (parseErr) {
        return reject(parseErr);
      }

      // Split file into an array of lines (preserve original newline style)
      const eol = data.includes('\r\n') ? '\r\n' : '\n';
      let lines = data.split(eol);

      try {
        for (const hunk of hunks) {
          lines = applyHunk(lines, hunk);
        }
      } catch (applyErr) {
        return reject(applyErr); // reject – **no partial write**
      }

      const newContent = lines.join(eol);

      // 2️⃣ Atomic write – same pattern the repo already uses.
      atomicWrite(absPath, newContent, (writeErr) => {
        if (writeErr) return reject(writeErr);
        resolve();
      });
    });
  });
}

// ------------------------------------------------------------------
// Export – make the new type visible to the rest of the system
// ------------------------------------------------------------------
module.exports = {
  // … existing exports …
  applyUdiff,
};
```

### How it fits into the existing workflow

1. **Gate stays unchanged** – The validation gate that runs before any edit is still invoked by the caller (e.g., `applyEdit(edit)`). The new `applyUdiff` simply assumes the gate has already approved the edit.

2. **Dispatch** – In the central edit‑dispatcher (likely a `switch(edit.type)`) add a case:

   ```js
   case 'udiff':
     return applyUdiff(edit.absPath, edit.patchText);
