// ------------------------------------------------------------
// testWorker.ts – a new CodeDNA test worker
// ------------------------------------------------------------

import {
  Worker,
  EventBus,
  Logger,
  Message,
  DeadLetterQueue,
} from '@codedna/core';

// -------------------------------------------------------------------
// 1. Configuration (you can adjust these values as needed)
// -------------------------------------------------------------------
const WORKER_NAME = 'test-worker';
const CONCURRENCY = 5;          // max parallel handlers
const BATCH_SIZE = 10;          // messages pulled per cycle
const PULL_TIMEOUT_MS = 2000;   // wait time before empty pull returns

// -------------------------------------------------------------------
// 2. Event handlers – add your test‑specific logic here
// -------------------------------------------------------------------
const handlers: Record<string, (msg: Message) => Promise<void>> = {
  // Example: a simple echo handler
  'echo': async (msg) => {
    Logger.info(`Echoing payload: ${JSON.stringify(msg.payload)}`);
    // ... any test‑specific verification can go here ...
  },

  // Add more handlers as required by your test suite
  // 'myEvent': async (msg) => { … }
};

// -------------------------------------------------------------------
// 3. Core processing loop (processEvents pattern)
// -------------------------------------------------------------------
async function processEvents(eventBus: EventBus): Promise<void> {
  while (true) {
    const messages = await eventBus.pull(BATCH_SIZE, PULL_TIMEOUT_MS);
    if (messages.length === 0) {
      // No work – give the event loop a breather
      await new Promise((r) => setTimeout(r, 500));
      continue;
    }

    // Process each message concurrently up to CONCURRENCY limit
    await Promise.all(
      messages.map(async (msg) => {
        const handler = handlers[msg.type];
        if (!handler) {
          Logger.warn(`No handler for event type "${msg.type}" – sending to DLQ`);
          await DeadLetterQueue.send(msg);
          await eventBus.ack(msg.id);
          return;
        }

        try {
          await handler(msg);
          await eventBus.ack(msg.id);
        } catch (err) {
          Logger.error(`Handler for "${msg.type}" failed: ${err}`);
          // Simple retry policy: send to DLQ after one failure
          await DeadLetterQueue.send(msg);
          await eventBus.ack(msg.id);
        }
      })
    );
  }
}

// -------------------------------------------------------------------
// 4. Worker bootstrap (startWorker pattern)
// -------------------------------------------------------------------
async function startWorker(): Promise<void> {
  const worker = new Worker({
    name: WORKER_NAME,
    concurrency: CONCURRENCY,
  });

  // Hook the processing loop into the worker lifecycle
  worker.onStart(async (eventBus) => {
    Logger.info(`${WORKER_NAME} started – listening for events`);
    await processEvents(eventBus);
  });

  // Graceful shutdown
  const shutdown = async () => {
    Logger.info('Shutdown signal received – stopping worker...');
    await worker.stop(); // waits for in‑flight handlers to finish
    process.exit(0);
  };
  process.on('SIGINT', shutdown);
  process.on('SIGTERM', shutdown);

  // Launch
  await worker.start();
}

// -------------------------------------------------------------------
// 5. Execute when this file is run directly
// -------------------------------------------------------------------
if (require.main === module) {
  startWorker().catch((e) => {
    Logger.error(`Failed to start ${WORKER_NAME}: ${e}`);
    process.exit(1);
  });
}
