import fs from "node:fs";
import path from "node:path";
import crypto from "node:crypto";

export function sha256File(filePath) {
  const data = fs.readFileSync(filePath);
  return crypto.createHash("sha256").update(data).digest("hex");
}

export function loadState(stateFile) {
  if (!fs.existsSync(stateFile)) return { version: 1, files: {} };
  const raw = fs.readFileSync(stateFile, "utf8");
  try {
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object" || !parsed.files) {
      return { version: 1, files: {} };
    }
    return parsed;
  } catch {
    return { version: 1, files: {} };
  }
}

export function saveState(stateFile, state) {
  const dir = path.dirname(stateFile);
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(stateFile, JSON.stringify(state, null, 2), "utf8");
}

export function diffHashes(prevFiles, nextFiles) {
  const changed = [];
  const deleted = [];

  for (const filePath of Object.keys(nextFiles)) {
    if (prevFiles[filePath] !== nextFiles[filePath]) changed.push(filePath);
  }
  for (const filePath of Object.keys(prevFiles)) {
    if (!(filePath in nextFiles)) deleted.push(filePath);
  }

  return { changed, deleted };
}
