export type SprintVelocity = {
  sprintId: string;
  sprintName: string;
  completedStoryPoints: number;
  endDate: string;
};

export function sortSprintsByEndDate(items: SprintVelocity[]): SprintVelocity[] {
  return [...items].sort((a, b) => {
    const aTime = new Date(a.endDate).getTime();
    const bTime = new Date(b.endDate).getTime();
    return aTime - bTime;
  });
}

export function averageVelocity(items: SprintVelocity[]): number {
  if (items.length === 0) return 0;
  const total = items.reduce((sum, sprint) => sum + sprint.completedStoryPoints, 0);
  return Number((total / items.length).toFixed(2));
}
