import { mkdtempSync, writeFileSync, rmSync } from "fs";
import { join } from "path";
import { tmpdir } from "os";
import { detectChangedFiles } from "./incremental.js";

function withTempDir(fn) {
  const dir = mkdtempSync(join(tmpdir(), "inc-hash-"));
  try {
    fn(dir);
  } finally {
    rmSync(dir, { recursive: true, force: true });
  }
}

withTempDir((dir) => {
  const a = join(dir, "a.txt");
  const b = join(dir, "b.txt");
  const manifest = join(dir, ".cache", "hashes.json");

  writeFileSync(a, "one\n", "utf8");
  writeFileSync(b, "two\n", "utf8");

  const first = detectChangedFiles([a, b], manifest);
  if (first.length !== 2) throw new Error("Expected first run to rebuild all");

  const second = detectChangedFiles([a, b], manifest);
  if (second.length !== 0) throw new Error("Expected second run to rebuild none");

  writeFileSync(b, "two changed\n", "utf8");
  const third = detectChangedFiles([a, b], manifest);
  if (third.length !== 1 || third[0] !== b) {
    throw new Error("Expected only changed file to rebuild");
  }
});

console.log("incremental hash test passed");
