export type Sprint = {
  id: string
  name: string
  startDate: string
  endDate: string
}

export type Story = {
  id: string
  sprintId: string
  points: number
  status: string
  completedAt?: string
}

export type VelocityPoint = {
  sprintId: string
  sprintName: string
  completedPoints: number
}

const isDone = (status: string): boolean => status.toLowerCase() === "done"

export function computeVelocityBySprint(
  sprints: Sprint[],
  stories: Story[]
): VelocityPoint[] {
  return sprints.map((sprint) => {
    const end = new Date(sprint.endDate).getTime()
    const completedPoints = stories
      .filter((story) => story.sprintId === sprint.id)
      .filter((story) => isDone(story.status))
      .filter((story) => {
        if (!story.completedAt) return true
        return new Date(story.completedAt).getTime() <= end
      })
      .reduce((sum, story) => sum + (story.points || 0), 0)

    return {
      sprintId: sprint.id,
      sprintName: sprint.name,
      completedPoints
    }
  })
}

export function computeAverageVelocity(points: VelocityPoint[]): number {
  if (points.length === 0) return 0
  const total = points.reduce((sum, p) => sum + p.completedPoints, 0)
  return Math.round((total / points.length) * 100) / 100
}
