import { createHash } from "node:crypto";
import { readFileSync } from "node:fs";

function computeContentHash(filePath) {
  const data = readFileSync(filePath);
  return createHash("sha256").update(data).digest("hex");
}

function shouldRebuild(filePath, stat, previous) {
  if (!previous) return true;
  const hash = computeContentHash(filePath);
  // Backward compatibility: if older cache entries lack hash, rebuild once.
  if (!previous.hash) return true;
  return previous.hash !== hash;
}

function snapshotFile(filePath, stat) {
  return {
    size: stat.size,
    hash: computeContentHash(filePath),
  };
}
