import { WysNode, NodeType } from "./types";

const mkId = (type: NodeType) =>
  `${type}-${Math.random().toString(36).slice(2, 8)}`;

export function findNode(node: WysNode, id: string): WysNode | null {
  if (node.id === id) return node;
  for (const child of node.children || []) {
    const found = findNode(child, id);
    if (found) return found;
  }
  return null;
}

export function updateNode(
  node: WysNode,
  id: string,
  patch: Partial<WysNode["props"]>
): WysNode {
  if (node.id === id) return { ...node, props: { ...node.props, ...patch } };
  return {
    ...node,
    children: (node.children || []).map((c) => updateNode(c, id, patch))
  };
}

export function addChild(node: WysNode, parentId: string, type: NodeType): WysNode {
  const fresh: WysNode = {
    id: mkId(type),
    type,
    props:
      type === "text"
        ? { text: "New text", fontSize: "16px" }
        : type === "button"
        ? { label: "Click", href: "#", variant: "secondary" }
        : type === "image"
        ? { src: "https://via.placeholder.com/320x160", alt: "Placeholder" }
        : { className: "section", padding: "12px" },
    children: type === "section" ? [] : undefined
  };

  if (node.id === parentId) {
    return { ...node, children: [...(node.children || []), fresh] };
  }
  return {
    ...node,
    children: (node.children || []).map((c) => addChild(c, parentId, type))
  };
}
