import React, { useMemo, useState } from "react";
import { defaultLayout } from "./defaultLayout";
import { addChild, findNode, updateNode } from "./treeOps";
import { BuilderState, NodeType, WysNode } from "./types";

const renderNode = (node: WysNode, select: (id: string) => void, selectedId: string | null) => {
  const selected = node.id === selectedId;
  const border = selected ? "2px solid #2563eb" : "1px dashed #d1d5db";
  const common = { border, padding: "8px", marginBottom: "8px", cursor: "pointer" as const };

  if (node.type === "text") {
    return <p style={{ ...common, fontSize: node.props.fontSize }} onClick={() => select(node.id)}>{node.props.text}</p>;
  }
  if (node.type === "button") {
    return <button style={common} onClick={() => select(node.id)}>{node.props.label}</button>;
  }
  if (node.type === "image") {
    return <img style={{ ...common, maxWidth: "100%" }} src={node.props.src} alt={node.props.alt || ""} onClick={() => select(node.id)} />;
  }
  return (
    <div style={{ ...common, padding: node.props.padding || "12px" }} onClick={() => select(node.id)}>
      {(node.children || []).map((c) => <div key={c.id}>{renderNode(c, select, selectedId)}</div>)}
    </div>
  );
};

export default function WysKitBuilder() {
  const [state, setState] = useState<BuilderState>({ root: defaultLayout, selectedId: "root" });
  const selected = useMemo(
    () => (state.selectedId ? findNode(state.root, state.selectedId) : null),
    [state.root, state.selectedId]
  );

  const onAdd = (type: NodeType) => {
    if (!state.selectedId) return;
    setState((s) => ({ ...s, root: addChild(s.root, s.selectedId!, type) }));
  };

  const onProp = (key: string, value: string) => {
    if (!state.selectedId) return;
    setState((s) => ({ ...s, root: updateNode(s.root, s.selectedId!, { [key]: value }) }));
  };

  return (
    <div style={{ display: "grid", gridTemplateColumns: "260px 1fr 280px", gap: "12px" }}>
      <aside>
        <h3>Blocks</h3>
        <button onClick={() => onAdd("section")}>+ Section</button>
        <button onClick={() => onAdd("text")}>+ Text</button>
        <button onClick={() => onAdd("button")}>+ Button</button>
        <button onClick={() => onAdd("image")}>+ Image</button>
      </aside>

      <main>
        <h3>Canvas</h3>
        {renderNode(state.root, (id) => setState((s) => ({ ...s, selectedId: id })), state.selectedId)}
      </main>

      <aside>
