import React, { useMemo, useState } from 'react';
import './KanbanBoard.css';

const COLUMNS = [
  { id: 'todo', title: 'To-Do' },
  { id: 'inprogress', title: 'In Progress' },
  { id: 'done', title: 'Done' }
];

const INITIAL_TASKS = [
  { id: 'T-1', title: 'Draft project brief', status: 'todo' },
  { id: 'T-2', title: 'Build API endpoint', status: 'inprogress' },
  { id: 'T-3', title: 'QA regression pass', status: 'done' }
];

export default function KanbanBoard() {
  const [tasks, setTasks] = useState(INITIAL_TASKS);
  const [draggedId, setDraggedId] = useState(null);

  const tasksByColumn = useMemo(() => {
    return COLUMNS.reduce((acc, col) => {
      acc[col.id] = tasks.filter((t) => t.status === col.id);
      return acc;
    }, {});
  }, [tasks]);

  const onDragStart = (taskId) => setDraggedId(taskId);

  const onDrop = (newStatus) => {
    if (!draggedId) return;
    setTasks((prev) =>
      prev.map((task) =>
        task.id === draggedId ? { ...task, status: newStatus } : task
      )
    );
    setDraggedId(null);
  };

  return (
    <div className="kanban-board" aria-label="Kanban Board">
      {COLUMNS.map((col) => (
        <section
          key={col.id}
          className="kanban-column"
          onDragOver={(e) => e.preventDefault()}
          onDrop={() => onDrop(col.id)}
          aria-label={col.title}
        >
          <h2>{col.title}</h2>
          <div className="kanban-cards">
            {tasksByColumn[col.id].map((task) => (
              <article
                key={task.id}
                className="kanban-card"
                draggable
                onDragStart={() => onDragStart(task.id)}
              >
                <p>{task.title}</p>
              </article>
            ))}
          </div>
        </section>
      ))}
    </div>
  );
}
