export type SprintRecord = {
  sprintId: string
  sprintName: string
  completedPoints: number
  endDate: string
}

export type VelocityPoint = {
  sprintId: string
  sprintName: string
  completedPoints: number
  endDate: string
}

export type VelocitySummary = {
  points: VelocityPoint[]
  averageVelocity: number
}

export function buildVelocitySummary(sprints: SprintRecord[]): VelocitySummary {
  const points = [...sprints]
    .sort((a, b) => new Date(a.endDate).getTime() - new Date(b.endDate).getTime())
    .map((s) => ({
      sprintId: s.sprintId,
      sprintName: s.sprintName,
      completedPoints: Math.max(0, Number(s.completedPoints) || 0),
      endDate: s.endDate
    }))

  const total = points.reduce((sum, p) => sum + p.completedPoints, 0)
  const averageVelocity = points.length ? Number((total / points.length).toFixed(2)) : 0

  return { points, averageVelocity }
}
