const state = {
  blocks: [],
  selectedId: null
};

const canvas = document.getElementById("canvas");
const inspector = document.getElementById("inspector");

document.getElementById("add-text").addEventListener("click", () => {
  addBlock({ type: "text", content: "Editable text" });
});
document.getElementById("add-button").addEventListener("click", () => {
  addBlock({ type: "button", content: "Click me" });
});
document.getElementById("export-json").addEventListener("click", () => {
  alert(JSON.stringify(state.blocks, null, 2));
});

function addBlock(partial) {
  const block = { id: crypto.randomUUID(), ...partial };
  state.blocks.push(block);
  state.selectedId = block.id;
  render();
}

function selectBlock(id) {
  state.selectedId = id;
  render();
}

function updateSelected(content) {
  const b = state.blocks.find(x => x.id === state.selectedId);
  if (!b) return;
  b.content = content;
  render();
}

function render() {
  canvas.innerHTML = "";
  for (const block of state.blocks) {
    const el = document.createElement(block.type === "button" ? "button" : "div");
    el.className = "block" + (block.id === state.selectedId ? " selected" : "");
    el.textContent = block.content;
    el.addEventListener("click", () => selectBlock(block.id));
    canvas.appendChild(el);
  }

  const sel = state.blocks.find(x => x.id === state.selectedId);
  if (!sel) {
    inspector.innerHTML = "<p>No block selected</p>";
    return;
  }

  inspector.innerHTML = `
    <label>Type</label>
    <div>${sel.type}</div>
    <label>Content</label>
    <input id="content-input" value="${escapeHtml(sel.content)}" />
  `;
  document.getElementById("content-input")
    .addEventListener("input", e => updateSelected(e.target.value));
}

function escapeHtml(s) {
  return s.replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;");
}

render();
