import React, { useMemo, useState } from 'react';

const COLUMNS = [
  { key: 'todo', title: 'To-Do' },
  { key: 'inprogress', title: 'In Progress' },
  { key: 'done', title: 'Done' }
];

const seedTasks = [
  { id: 't1', title: 'Design login page', status: 'todo' },
  { id: 't2', title: 'API integration', status: 'inprogress' },
  { id: 't3', title: 'Release checklist', status: 'done' }
];

export default function KanbanBoard() {
  const [tasks, setTasks] = useState(seedTasks);
  const [draggedId, setDraggedId] = useState(null);

  const grouped = useMemo(() => {
    const map = { todo: [], inprogress: [], done: [] };
    tasks.forEach((task) => map[task.status].push(task));
    return map;
  }, [tasks]);

  function onDragStart(taskId) {
    setDraggedId(taskId);
  }

  function onDrop(nextStatus) {
    if (!draggedId) return;
    setTasks((prev) =>
      prev.map((t) => (t.id === draggedId ? { ...t, status: nextStatus } : t))
    );
    setDraggedId(null);
  }

  return (
    <div style={styles.board} aria-label="Kanban Board">
      {COLUMNS.map((col) => (
        <section
          key={col.key}
          style={styles.column}
          onDragOver={(e) => e.preventDefault()}
          onDrop={() => onDrop(col.key)}
          aria-label={col.title}
        >
          <h2 style={styles.title}>{col.title}</h2>
          {grouped[col.key].map((task) => (
            <article
              key={task.id}
              draggable
              onDragStart={() => onDragStart(task.id)}
              style={styles.card}
            >
              {task.title}
            </article>
          ))}
        </section>
      ))}
    </div>
  );
}

const styles = {
  board: {
    display: 'grid',
    gridTemplateColumns: 'repeat(3, 1fr)',
    gap: '16px',
    padding: '16px'
  },
  column: {
    background: '#f4f5f7',
    borderRadius: '8px',
    minHeight: '280px',
    padding: '12px'
  },
  title: {
    margin: '0 0 12px',
    fontSize: '16px'
  },
