export type SprintVelocity = {
  sprintId: string;
  sprintName: string;
  completedPoints: number;
  endDate: string;
};

export type VelocitySummary = {
  sprints: SprintVelocity[];
  averageVelocity: number;
};

export function calculateAverageVelocity(sprints: SprintVelocity[]): number {
  if (!sprints.length) return 0;
  const total = sprints.reduce((sum, s) => sum + s.completedPoints, 0);
  return Math.round((total / sprints.length) * 100) / 100;
}

export function buildVelocitySummary(sprints: SprintVelocity[]): VelocitySummary {
  const ordered = [...sprints].sort(
    (a, b) => new Date(a.endDate).getTime() - new Date(b.endDate).getTime()
  );
  return {
    sprints: ordered,
    averageVelocity: calculateAverageVelocity(ordered),
  };
}
