export function createInitialState(state = { blocks: [], selectedBlockId: null }) {
  return state;
}

export function addBlock(state, block) {
  return { ...state, blocks: [...state.blocks, block] };
}

export function selectBlock(state, blockId) {
  return { ...state, selectedBlockId: blockId };
}

export function updateBlockProps(state, blockId, nextProps) {
  const blocks = state.blocks.map((b) =>
    b.id === blockId ? { ...b, props: { ...b.props, ...nextProps } } : b
  );
  return { ...state, blocks };
}
