export function renderBlock(block) {
  if (block.type === "text") {
    const text = block.props.text || "Editable text";
    return `<div class="wk-block wk-text">${text}</div>`;
  }

  if (block.type === "image") {
    const src = block.props.src || "https://via.placeholder.com/320x180";
    const alt = block.props.alt || "Image block";
    return `<img class="wk-block wk-image" src="${src}" alt="${alt}" />`;
  }

  if (block.type === "button") {
    const label = block.props.label || "Click";
    return `<button class="wk-block wk-button">${label}</button>`;
  }

  return `<div class="wk-block">Unknown block</div>`;
}
