import { createInitialState, addBlock, selectBlock } from "../core/state.js";
import { renderBlock } from "./renderBlock.js";

let state = createInitialState();

function uid() {
  return Math.random().toString(36).slice(2, 10);
}

function makeBlock(type) {
  if (type === "text") return { id: uid(), type, props: { text: "New text" } };
  if (type === "image") return { id: uid(), type, props: { src: "", alt: "" } };
  return { id: uid(), type: "button", props: { label: "New button" } };
}

function draw() {
  const canvas = document.querySelector("#wk-canvas");
  canvas.innerHTML = state.blocks
    .map((b) => `<div data-id="${b.id}" class="wk-item">${renderBlock(b)}</div>`)
    .join("");

  document.querySelector("#wk-state").textContent = JSON.stringify(state, null, 2);

  canvas.querySelectorAll(".wk-item").forEach((el) => {
    el.onclick = () => {
      state = selectBlock(state, el.dataset.id);
      draw();
    };
    if (state.selectedBlockId === el.dataset.id) el.classList.add("selected");
  });
}

export function mountWysKit(root) {
  root.innerHTML = `
    <section class="wk-shell">
      <aside class="wk-toolbar">
        <h3>WysKit</h3>
        <button data-add="text">+ Text</button>
        <button data-add="image">+ Image</button>
        <button data-add="button">+ Button</button>
      </aside>
      <main id="wk-canvas" class="wk-canvas"></main>
      <pre id="wk-state" class="wk-state"></pre>
    </section>
  `;

  root.querySelectorAll("[data-add]").forEach((btn) => {
    btn.onclick = () => {
      state = addBlock(state, makeBlock(btn.dataset.add));
      draw();
    };
  });

  draw();
}
