import { useMemo, useState } from "react";
import "./KanbanBoard.css";

const INITIAL = {
  todo: [
    { id: "t1", title: "Set up project board" },
    { id: "t2", title: "Define acceptance criteria" }
  ],
  inprogress: [{ id: "t3", title: "Build Kanban UI" }],
  done: [{ id: "t4", title: "Create ticket #24" }]
};

const COLUMNS = [
  { key: "todo", label: "To-Do" },
  { key: "inprogress", label: "In Progress" },
  { key: "done", label: "Done" }
];

export default function KanbanBoard() {
  const [board, setBoard] = useState(INITIAL);
  const [drag, setDrag] = useState(null);

  const counts = useMemo(
    () =>
      COLUMNS.reduce((acc, c) => {
        acc[c.key] = board[c.key].length;
        return acc;
      }, {}),
    [board]
  );

  const onDragStart = (e, fromCol, cardId) => {
    setDrag({ fromCol, cardId });
    e.dataTransfer.effectAllowed = "move";
  };

  const onDrop = (e, toCol) => {
    e.preventDefault();
    if (!drag) return;
    const { fromCol, cardId } = drag;
    if (fromCol === toCol) return setDrag(null);

    setBoard((prev) => {
      const card = prev[fromCol].find((c) => c.id === cardId);
      if (!card) return prev;
      return {
        ...prev,
        [fromCol]: prev[fromCol].filter((c) => c.id !== cardId),
        [toCol]: [...prev[toCol], card]
      };
    });
    setDrag(null);
  };

  return (
    <section className="kanban">
      {COLUMNS.map((col) => (
        <div
          key={col.key}
          className="kanban-col"
          onDragOver={(e) => e.preventDefault()}
          onDrop={(e) => onDrop(e, col.key)}
        >
          <header className="kanban-col-head">
            <h3>{col.label}</h3>
            <span>{counts[col.key]}</span>
          </header>
          <div className="kanban-cards">
            {board[col.key].map((card) => (
              <article
                key={card.id}
                className="kanban-card"
                draggable
                onDragStart={(e) => onDragStart(e, col.key, card.id)}
              >
                {card.title}
              </article>
            ))}
          </div>
        </div>
      ))}
    </section>
  );
}
