export type SprintVelocity = {
  sprintId: string;
  sprintName: string;
  completedPoints: number;
  isClosed: boolean;
};

export type VelocityResult = {
  pointsBySprint: Array<{ sprintId: string; sprintName: string; completedPoints: number }>;
  averageVelocity: number;
};

export function computeVelocity(sprints: SprintVelocity[]): VelocityResult {
  const closed = sprints.filter(s => s.isClosed);
  const pointsBySprint = closed.map(s => ({
    sprintId: s.sprintId,
    sprintName: s.sprintName,
    completedPoints: s.completedPoints
  }));

  const total = pointsBySprint.reduce((sum, s) => sum + s.completedPoints, 0);
  const averageVelocity = pointsBySprint.length === 0 ? 0 : Number((total / pointsBySprint.length).toFixed(2));

  return { pointsBySprint, averageVelocity };
}
