import { useEffect, useState } from "react";
import { addFunds, createPayment, getTransactions, getWallet } from "../api/paymentsClient";
import PaymentForm from "../components/PaymentForm";
import WalletCard from "../components/WalletCard";
import TransactionList from "../components/TransactionList";

export default function PaymentsPage() {
  const [wallet, setWallet] = useState(null);
  const [transactions, setTransactions] = useState([]);
  const [busy, setBusy] = useState(false);
  const [message, setMessage] = useState("");

  async function loadData() {
    const [walletData, txData] = await Promise.all([getWallet(), getTransactions()]);
    setWallet(walletData);
    setTransactions(txData || []);
  }

  useEffect(() => {
    loadData().catch((e) => setMessage(e.message));
  }, []);

  async function handlePayment(payload) {
    setBusy(true);
    setMessage("");
    try {
      await createPayment(payload);
      setMessage("Payment sent successfully.");
      await loadData();
    } catch (e) {
      setMessage(`Payment failed: ${e.message}`);
    } finally {
      setBusy(false);
    }
  }

  async function handleTopUp(payload) {
    setBusy(true);
    setMessage("");
    try {
      await addFunds(payload);
      setMessage("Wallet funded.");
      await loadData();
    } catch (e) {
      setMessage(`Top-up failed: ${e.message}`);
    } finally {
      setBusy(false);
    }
  }

  return (
    <main className="payments-layout">
      <h1>Payments</h1>
      {message && <p role="status">{message}</p>}
      <div className="grid">
        <PaymentForm onSubmit={handlePayment} loading={busy} />
        <WalletCard wallet={wallet} onTopUp={handleTopUp} loading={busy} />
      </div>
      <TransactionList items={transactions} />
    </main>
  );
}
