import { useMemo, useState } from 'react';  
import './kanban.css';  

const COLUMNS = [  
  { id: 'todo', title: 'To-Do' },  
  { id: 'inprogress', title: 'In Progress' },  
  { id: 'done', title: 'Done' }  
];  

const SEED = [  
  { id: 'T-1', title: 'Create board layout', status: 'todo' },  
  { id: 'T-2', title: 'Implement drag-drop', status: 'inprogress' },  
  { id: 'T-3', title: 'Polish UI', status: 'done' }  
];  

export default function KanbanBoard() {  
  const [cards, setCards] = useState(SEED);  
  const [draggingId, setDraggingId] = useState(null);  

  const grouped = useMemo(() => {  
    return COLUMNS.reduce((acc, c) => {  
      acc[c.id] = cards.filter(card => card.status === c.id);  
      return acc;  
    }, {});  
  }, [cards]);  

  const onDrop = (nextStatus) => {  
    if (!draggingId) return;  
    setCards(prev =>  
      prev.map(card =>  
        card.id === draggingId ? { ...card, status: nextStatus } : card  
      )  
    );  
    setDraggingId(null);  
  };  

  return (  
    <div className="kanban-board">  
      {COLUMNS.map(col => (  
        <section  
          key={col.id}  
          className="kanban-column"  
          onDragOver={(e) => e.preventDefault()}  
          onDrop={() => onDrop(col.id)}  
        >  
          <h2>{col.title}</h2>  
          <div className="kanban-list">  
            {grouped[col.id].map(card => (  
              <article  
                key={card.id}  
                className="kanban-card"  
                draggable  
                onDragStart={() => setDraggingId(card.id)}  
                onDragEnd={() => setDraggingId(null)}  
              >  
                {card.title}  
              </article>  
            ))}  
          </div>  
        </section>  
      ))}  
    </div>  
  );  
}  
