export type SprintPoints = { sprint: string; points: number };

export function averageVelocity(rows: SprintPoints[]): number {
  if (!rows.length) return 0;
  const total = rows.reduce((sum, r) => sum + r.points, 0);
  return Number((total / rows.length).toFixed(2));
}

export function buildVelocitySeries(
  completedBySprint: Record<string, number>
): SprintPoints[] {
  return Object.entries(completedBySprint)
    .map(([sprint, points]) => ({ sprint, points }))
    .sort((a, b) => a.sprint.localeCompare(b.sprint));
}
