});

export const getActivePage = (state) =>
  state.pages.find((p) => p.id === state.activePageId);

export const addBlock = (state, type) => {
  const page = getActivePage(state);
  if (!page) return state;
  const id = `b-${Date.now()}`;
  const defaults = {
    heading: "New heading",
    paragraph: "New paragraph",
    button: "Click me"
  };
  page.blocks.push({ id, type, text: defaults[type] || "New block" });
  state.selectedBlockId = id;
  return state;
};

export const updateBlockText = (state, blockId, text) => {
  const page = getActivePage(state);
  if (!page) return state;
  const block = page.blocks.find((b) => b.id === blockId);
  if (!block) return state;
  block.text = text;
  return state;
};

export const selectBlock = (state, blockId) => {
  state.selectedBlockId = blockId;
  return state;
};
