import { getActivePage } from "./model.js";

const blockTag = (type) => {
  if (type === "heading") return "h2";
  if (type === "button") return "button";
  return "p";
};

export const renderCanvas = (state, canvasEl) => {
  const page = getActivePage(state);
  canvasEl.innerHTML = "";
  if (!page) return;

  page.blocks.forEach((block) => {
    const el = document.createElement(blockTag(block.type));
    el.className = "wk-block";
    if (state.selectedBlockId === block.id) el.classList.add("selected");
    el.dataset.blockId = block.id;
    el.textContent = block.text;
    canvasEl.appendChild(el);
  });
};

export const renderInspector = (state, inspectorEl, onInput) => {
  const page = getActivePage(state);
  inspectorEl.innerHTML = "";
  if (!page || !state.selectedBlockId) {
    inspectorEl.innerHTML = "<p>Select a block to edit.</p>";
    return;
  }

  const block = page.blocks.find((b) => b.id === state.selectedBlockId);
  if (!block) return;

  const label = document.createElement("label");
  label.textContent = "Text";

  const input = document.createElement("textarea");
  input.value = block.text;
  input.rows = 6;
  input.addEventListener("input", (e) => onInput(e.target.value));

  inspectorEl.appendChild(label);
  inspectorEl.appendChild(input);
};
