export type Sprint = {
  id: string
  name: string
  startDate: string
  endDate: string
}

export type Story = {
  id: string
  sprintId: string | null
  storyPoints: number | null
  status: string
  completedAt: string | null
}

export type SprintVelocity = {
  sprintId: string
  sprintName: string
  completedPoints: number
}

export function calculateSprintVelocity(sprints: Sprint[], stories: Story[]): SprintVelocity[] {
  const doneStatuses = new Set(["Done", "Closed", "Accepted"])

  return sprints.map((sprint) => {
    const completedPoints = stories
      .filter((story) => {
        if (!story.sprintId || story.sprintId !== sprint.id) return false
        if (!doneStatuses.has(story.status)) return false
        if (!story.completedAt) return false

        const completed = new Date(story.completedAt).getTime()
        const start = new Date(sprint.startDate).getTime()
        const end = new Date(sprint.endDate).getTime()

        return completed >= start && completed <= end
      })
      .reduce((sum, story) => sum + (story.storyPoints ?? 0), 0)

    return {
      sprintId: sprint.id,
      sprintName: sprint.name,
      completedPoints
    }
  })
}

export function calculateAverageVelocity(items: SprintVelocity[]): number {
  if (items.length === 0) return 0
  const total = items.reduce((sum, item) => sum + item.completedPoints, 0)
  return Number((total / items.length).toFixed(2))
}
