import { useState } from "react";
import { saveStoryPoints } from "../../services/stories";

const ALLOWED = [0, 1, 2, 3, 5, 8, 13, 21];

type Props = {
  storyId: string;
  value: number | null;
  version: number;
  canEdit: boolean;
  onSaved: (points: number, version: number) => void;
};

export default function StoryPointCell({ storyId, value, version, canEdit, onSaved }: Props) {
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState(value ?? 0);
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState("");

  async function submit() {
    if (!ALLOWED.includes(Number(draft))) {
      setError("Story points must be one of: 0, 1, 2, 3, 5, 8, 13, 21");
      return;
    }
    setBusy(true);
    setError("");
    try {
      const res = await saveStoryPoints(storyId, Number(draft), version);
      onSaved(res.points, res.version);
      setEditing(false);
    } catch (e: any) {
      setError(e?.message ?? "Failed to save story points");
    } finally {
      setBusy(false);
    }
  }

  if (!canEdit) return <span>{value ?? "—"}</span>;

  if (!editing) {
    return (
      <button type="button" className="sp-chip" onClick={() => setEditing(true)}>
        {value ?? "Set"}
      </button>
    );
  }

  return (
    <div className="sp-editor">
      <input
        aria-label="Story points"
        type="number"
        value={draft}
        onChange={(e) => setDraft(Number(e.target.value))}
        disabled={busy}
      />
      <button type="button" onClick={submit} disabled={busy}>Save</button>
      <button type="button" onClick={() => setEditing(false)} disabled={busy}>Cancel</button>
      {error ? <small className="error">{error}</small> : null}
    </div>
  );
}
