import { PaymentRecord, PaymentRequest, WalletBalance } from "./types";

const wait = (ms: number) => new Promise((r) => setTimeout(r, ms));

let wallet: WalletBalance[] = [
  { currency: "USD", available: 1200 },
  { currency: "EUR", available: 300 },
  { currency: "GBP", available: 150 }
];

let payments: PaymentRecord[] = [];

export async function getWalletBalances(): Promise<WalletBalance[]> {
  await wait(150);
  return [...wallet];
}

export async function listPayments(): Promise<PaymentRecord[]> {
  await wait(150);
  return [...payments].sort((a, b) => b.createdAt.localeCompare(a.createdAt));
}

export async function createPayment(input: PaymentRequest): Promise<PaymentRecord> {
  await wait(250);
  const id = `pay_${Math.random().toString(36).slice(2, 10)}`;
  const record: PaymentRecord = {
    ...input,
    id,
    status: "succeeded",
    createdAt: new Date().toISOString()
  };
  payments.push(record);
  wallet = wallet.map((b) =>
    b.currency === input.currency
      ? { ...b, available: Math.max(0, b.available - input.amount) }
      : b
  );
  return record;
}
