import { useState } from "react";
import { updateStoryPoints } from "../../services/stories";

type Props = {
  storyId: string;
  value: number | null;
  version?: number;
  canEdit: boolean;
  onSaved: (value: number | null, version?: number) => void;
};

const ALLOWED = new Set([1, 2, 3, 5, 8, 13, 21]);

export function StoryPointCell({ storyId, value, version, canEdit, onSaved }: Props) {
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState(value?.toString() ?? "");
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");

  const validate = (raw: string): number | null => {
    if (raw.trim() === "") return null;
    const n = Number(raw);
    if (!Number.isInteger(n) || n < 0) throw new Error("Story points must be a non-negative integer.");
    if (!ALLOWED.has(n)) throw new Error("Use allowed values: 1, 2, 3, 5, 8, 13, 21.");
    return n;
  };

  const save = async () => {
    try {
      setError("");
      setSaving(true);
      const next = validate(draft);
      const res = await updateStoryPoints({ storyId, storyPoints: next, version });
      onSaved(res.storyPoints, res.version);
      setEditing(false);
    } catch (e: any) {
      setError(e?.message ?? "Failed to update story points.");
    } finally {
      setSaving(false);
    }
  };

  if (!canEdit) return <span>{value ?? "—"}</span>;

  if (!editing) {
    return (
      <button type="button" className="sp-inline-trigger" onClick={() => setEditing(true)}>
        {value ?? "—"}
      </button>
    );
  }

  return (
    <div className="sp-inline-editor">
      <input
        aria-label="Story points"
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onKeyDown={(e) => {
          if (e.key === "Enter") void save();
          if (e.key === "Escape") {
            setDraft(value?.toString() ?? "");
            setEditing(false);
            setError("");
          }
        }}
        disabled={saving}
      />
      <button type="button" onClick={() => void save()} disabled={saving}>Save</button>
      <button
        type="button"
        onClick={() => {
          setDraft(value?.toString() ?? "");
          setEditing(false);
          setError("");
        }}
        disabled={saving}
      >
        Cancel
      </button>
      {error ? <p className="field-error">{error}</p> : null}
    </div>
  );
}
