    private readonly repo: ArtifactRepository,
    private readonly storage: StorageService
  ) {}

  async createArtifact(input: CreateArtifactInput) {
    const id = randomUUID();
    const storageKey = buildArtifactKey(input.analysisId, input.kind, id);

    await this.storage.putObject({
      key: storageKey,
      body: input.data,
      contentType: input.mimeType
    });

    return this.repo.create({
      analysisId: input.analysisId,
      kind: input.kind,
      storageKey,
      mimeType: input.mimeType,
      byteSize: input.data.byteLength
    });
  }

  async getArtifactContent(artifactId: string) {
    const artifact = await this.repo.findById(artifactId);
    if (!artifact) return null;
    const content = await this.storage.getObject({ key: artifact.storageKey });
    return { artifact, content };
  }

  async listArtifactsForAnalysis(analysisId: string) {
    return this.repo.listByAnalysisId(analysisId);
  }
}
