import { useState } from "react";
import { updateStoryPoints } from "../../services/storyApi";

type Props = {
  storyId: string;
  value: number | null;
  version: number;
  canEdit: boolean;
  onSaved: (next: { points: number; version: number }) => void;
};

const ALLOWED = [0, 1, 2, 3, 5, 8, 13, 21];

export default function StoryPointCell({
  storyId,
  value,
  version,
  canEdit,
  onSaved
}: Props) {
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState(value ?? 0);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");

  if (!canEdit) return <span>{value ?? "—"}</span>;

  async function save() {
    setError("");
    if (!ALLOWED.includes(draft)) {
      setError("Invalid story points");
      return;
    }

    setSaving(true);
    const prev = value ?? 0;

    try {
      const res = await updateStoryPoints({
        storyId,
        points: draft,
        version
      });
      onSaved({ points: res.points, version: res.version });
      setEditing(false);
    } catch (e: any) {
      setDraft(prev);
      setError(e?.message || "Save failed");
    } finally {
      setSaving(false);
    }
  }

  if (!editing) {
    return (
      <button
        type="button"
        onClick={() => {
          setDraft(value ?? 0);
          setEditing(true);
        }}
      >
        {value ?? "—"}
      </button>
    );
  }

  return (
    <div>
      <input
        aria-label="Story points"
        type="number"
        value={draft}
        onChange={(e) => setDraft(Number(e.target.value))}
        disabled={saving}
      />
      <button type="button" onClick={save} disabled={saving}>Save</button>
      <button type="button" onClick={() => setEditing(false)} disabled={saving}>Cancel</button>
      {error ? <small role="alert">{error}</small> : null}
    </div>
  );
}
