import { Request, Response } from "express";
import { storyRepo } from "../repos/storyRepo";

const ALLOWED = [0, 1, 2, 3, 5, 8, 13, 21];

export async function updateStoryPointsHandler(req: Request, res: Response) {
  const id = req.params.id;
  const { points, version } = req.body as { points: number; version: number };

  if (!ALLOWED.includes(points)) {
    return res.status(400).json({ message: "Invalid story points" });
  }

  const updated = await storyRepo.updatePointsIfVersionMatches(id, points, version);
  if (!updated) {
    return res.status(409).json({ message: "Story was updated by someone else" });
  }

  return res.json({ points: updated.points, version: updated.version });
}
