import { createHash, randomUUID } from "crypto";
import { ArtifactKind, ArtifactRecord } from "./artifact.types";
import { StorageAdapter } from "./storage.adapter";

export interface ArtifactRepo {
  insert(row: ArtifactRecord): Promise<void>;
  findByAnalysisId(analysisId: string): Promise<ArtifactRecord[]>;
  findById(id: string): Promise<ArtifactRecord | null>;
}

export class ArtifactService {
  constructor(
    private readonly repo: ArtifactRepo,
    private readonly storage: StorageAdapter
  ) {}

  async save(params: {
    analysisId: string;
    kind: ArtifactKind;
    filename: string;
    mimeType: string;
    content: Buffer;
  }): Promise<ArtifactRecord> {
    const id = randomUUID();
    const checksumSha256 = createHash("sha256")
      .update(params.content)
      .digest("hex");
    const storageKey = `${params.analysisId}/${id}/${params.filename}`;

    await this.storage.put({
      key: storageKey,
      content: params.content,
      mimeType: params.mimeType,
    });

    const row: ArtifactRecord = {
      id,
      analysisId: params.analysisId,
      kind: params.kind,
      storageKey,
      filename: params.filename,
      mimeType: params.mimeType,
      sizeBytes: params.content.length,
      checksumSha256,
      createdAt: new Date().toISOString(),
    };

    await this.repo.insert(row);
    return row;
  }

  listByAnalysis(analysisId: string): Promise<ArtifactRecord[]> {
    return this.repo.findByAnalysisId(analysisId);
  }

  getById(id: string): Promise<ArtifactRecord | null> {
    return this.repo.findById(id);
  }
}
