import { useEffect, useState } from "react";
import { PaymentForm } from "../../components/payments/PaymentForm";
import { PaymentsTable } from "../../components/payments/PaymentsTable";
import { WalletCard } from "../../components/payments/WalletCard";
import { createPayment, listPayments, getWallet } from "../../services/paymentsApi";

type Payment = {
  id: string;
  amount: number;
  currency: string;
  recipient: string;
  status: "pending" | "completed" | "failed";
  createdAt: string;
};

type Wallet = {
  balance: number;
  currency: string;
};

export default function PaymentsPage() {
  const [payments, setPayments] = useState<Payment[]>([]);
  const [wallet, setWallet] = useState<Wallet | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const load = async () => {
    setLoading(true);
    setError("");
    try {
      const [p, w] = await Promise.all([listPayments(), getWallet()]);
      setPayments(p);
      setWallet(w);
    } catch (e: any) {
      setError(e?.message || "Failed to load payments data");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const handleCreate = async (input: { amount: number; currency: string; recipient: string }) => {
    setError("");
    try {
      const newPayment = await createPayment(input);
      setPayments((prev) => [newPayment, ...prev]);
      await load();
    } catch (e: any) {
      setError(e?.message || "Payment failed");
    }
  };

  return (
    <main style={{ maxWidth: 960, margin: "0 auto", padding: 16 }}>
      <h1>Payments</h1>
      {error && <p style={{ color: "crimson" }}>{error}</p>}
      {wallet && <WalletCard wallet={wallet} />}
      <PaymentForm onSubmit={handleCreate} />
      <PaymentsTable rows={payments} loading={loading} />
    </main>
  );
}
