import fs from "node:fs/promises";
import path from "node:path";
import crypto from "node:crypto";

const ROOT = process.env.ARTIFACT_ROOT ?? "var/artifacts";

export async function saveArtifactFile(input: {
  analysisId: string;
  filename: string;
  content: Buffer;
}) {
  const safeName = input.filename.replace(/[^\w.\-]/g, "_");
  const dir = path.join(ROOT, input.analysisId);
  await fs.mkdir(dir, { recursive: true });
  const filePath = path.join(dir, `${Date.now()}_${safeName}`);
  await fs.writeFile(filePath, input.content);
  const hash = crypto.createHash("sha256").update(input.content).digest("hex");
  return {
    storagePath: filePath,
    sizeBytes: input.content.byteLength,
    checksumSha256: hash
  };
}

export async function readArtifactFile(storagePath: string) {
  return fs.readFile(storagePath);
}
