import { Request, Response } from "express";
import { fetchArtifactContent, getArtifactsForAnalysis, storeArtifact } from "./artifact.service";

export async function uploadArtifact(req: Request, res: Response) {
  const { analysisId, kind } = req.body;
  const file = req.file;
  if (!analysisId || !kind || !file) {
    return res.status(400).json({ error: "analysisId, kind and file are required" });
  }

  const artifact = await storeArtifact({
    analysisId,
    kind,
    filename: file.originalname,
    mimeType: file.mimetype,
    content: file.buffer
  });

  return res.status(201).json({
    id: artifact.id,
    analysisId: artifact.analysisId,
    kind: artifact.kind,
    filename: artifact.filename,
    mimeType: artifact.mimeType,
    sizeBytes: artifact.sizeBytes,
    createdAt: artifact.createdAt
  });
}

export async function listAnalysisArtifacts(req: Request, res: Response) {
  const { analysisId } = req.params;
  const artifacts = await getArtifactsForAnalysis(analysisId);
  return res.json(artifacts.map(a => ({
    id: a.id,
    kind: a.kind,
    filename: a.filename,
    mimeType: a.mimeType,
    sizeBytes: a.sizeBytes,
    createdAt: a.createdAt,
    downloadUrl: `/api/artifacts/${a.id}/download`
  })));
}

export async function downloadArtifact(req: Request, res: Response) {
  const result = await fetchArtifactContent(req.params.id);
  if (!result) return res.status(404).json({ error: "Artifact not found" });

  res.setHeader("Content-Type", result.artifact.mimeType);
  res.setHeader("Content-Disposition", `inline; filename="${result.artifact.filename}"`);
  return res.send(result.content);
}
