import { useState } from "react";

type Props = {
  storyId: string;
  value: number | null;
  version: number;
  onSaved: (next: { points: number; version: number }) => void;
};

const ALLOWED = [1, 2, 3, 5, 8, 13];

export function StoryPointCell({ storyId, value, version, onSaved }: Props) {
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState(value?.toString() ?? "");
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState("");

  async function save() {
    setError("");
    const parsed = Number(draft);
    if (!Number.isInteger(parsed) || !ALLOWED.includes(parsed)) {
      setError(`Use one of: ${ALLOWED.join(", ")}`);
      return;
    }

    setBusy(true);
    const res = await fetch(`/api/stories/${storyId}/points`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ points: parsed, version })
    });
    setBusy(false);

    if (res.status === 409) {
      setError("Story was updated by someone else. Refresh and retry.");
      return;
    }
    if (!res.ok) {
      setError("Failed to save points.");
      return;
    }

    const data = await res.json();
    onSaved({ points: data.points, version: data.version });
    setEditing(false);
  }

  if (!editing) {
    return (
      <button onClick={() => setEditing(true)} className="sp-inline-btn">
        {value ?? "—"}
      </button>
    );
  }

  return (
    <div className="sp-inline-edit">
      <input
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        inputMode="numeric"
        aria-label="Story points"
      />
      <button disabled={busy} onClick={save}>Save</button>
      <button disabled={busy} onClick={() => setEditing(false)}>Cancel</button>
      {error ? <div className="sp-error">{error}</div> : null}
    </div>
  );
}
