import { useState } from "react";

type Props = {
  storyId: string;
  value: number | null;
  version: number;
  onSaved: (nextPoints: number | null, nextVersion: number) => void;
};

const isValidPoints = (raw: string) => {
  if (raw.trim() === "") return true; // allow clearing to null
  const n = Number(raw);
  return Number.isInteger(n) && n >= 0 && n <= 100;
};

export function StoryPointsInlineEditor({ storyId, value, version, onSaved }: Props) {
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState(value?.toString() ?? "");
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");

  async function save() {
    if (!isValidPoints(draft)) {
      setError("Story points must be an integer between 0 and 100.");
      return;
    }
    setSaving(true);
    setError("");
    const nextPoints = draft.trim() === "" ? null : Number(draft);

    const res = await fetch(`/api/stories/${storyId}/story-points`, {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
        "If-Match-Version": String(version)
      },
      body: JSON.stringify({ storyPoints: nextPoints })
    });

    if (res.status === 409) {
      setSaving(false);
      setError("Conflict detected. Refresh and retry.");
      return;
    }
    if (!res.ok) {
      setSaving(false);
      setError("Failed to save story points.");
      return;
    }

    const data = await res.json();
    onSaved(data.storyPoints, data.version);
    setSaving(false);
    setEditing(false);
  }

  if (!editing) {
    return (
      <button type="button" className="sp-chip" onClick={() => setEditing(true)}>
        {value ?? "—"}
      </button>
    );
  }

  return (
    <div className="sp-editor">
      <input
        aria-label="Story points"
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onKeyDown={(e) => {
          if (e.key === "Enter") void save();
          if (e.key === "Escape") {
            setDraft(value?.toString() ?? "");
            setEditing(false);
            setError("");
          }
        }}
        disabled={saving}
        inputMode="numeric"
      />
      <button type="button" onClick={() => void save()} disabled={saving}>Save</button>
      <button
        type="button"
        onClick={() => {
          setDraft(value?.toString() ?? "");
          setEditing(false);
          setError("");
        }}
        disabled={saving}
      >
        Cancel
      </button>
      {error ? <p className="sp-error">{error}</p> : null}
    </div>
  );
}
