storyPointsRouter.patch("/api/stories/:id/story-points", async (req, res) => {
  const storyId = req.params.id;
  const ifMatchVersion = Number(req.header("If-Match-Version"));
  const { storyPoints } = req.body as { storyPoints: number | null };

  if (!(storyPoints === null || (Number.isInteger(storyPoints) && storyPoints >= 0 && storyPoints <= 100))) {
    return res.status(400).json({ error: "Invalid storyPoints" });
  }
  if (!Number.isInteger(ifMatchVersion)) {
    return res.status(400).json({ error: "Missing If-Match-Version" });
  }

  const current = await req.app.locals.db.story.findById(storyId);
  if (!current) return res.status(404).json({ error: "Story not found" });
  if (current.version !== ifMatchVersion) return res.status(409).json({ error: "Version conflict" });

  const updated = await req.app.locals.db.story.update(storyId, {
    storyPoints,
    version: current.version + 1
  });

  return res.json({ id: updated.id, storyPoints: updated.storyPoints, version: updated.version });
});
