import crypto from "crypto";
import { Artifact } from "./artifact.model";
import { artifactStore } from "./artifact.store";

type CreateArtifactInput = {
  analysisId: string;
  type: "result" | "diagram" | "report";
  title: string;
  mimeType: string;
  payload: Buffer;
  createdBy: string;
  metadata?: Record<string, unknown>;
};

export async function createArtifact(input: CreateArtifactInput) {
  const checksumSha256 = crypto.createHash("sha256").update(input.payload).digest("hex");
  const storageKey = `analysis/${input.analysisId}/${Date.now()}-${input.type}`;
  await artifactStore.put(storageKey, input.payload, input.mimeType);

  return Artifact.create({
    analysisId: input.analysisId,
    type: input.type,
    title: input.title,
    mimeType: input.mimeType,
    storageKey,
    sizeBytes: input.payload.byteLength,
    checksumSha256,
    createdBy: input.createdBy,
    metadata: input.metadata ?? {}
  });
}

export async function listArtifacts(analysisId: string, type?: string) {
  const filter: Record<string, unknown> = { analysisId };
  if (type) filter.type = type;
  return Artifact.find(filter).sort({ createdAt: -1 }).lean();
}

export async function getArtifactDownload(artifactId: string) {
  const artifact = await Artifact.findById(artifactId).lean();
