import { Request, Response } from "express";
import { createArtifact, getArtifactDownload, listArtifacts } from "./artifact.service";

export async function uploadArtifact(req: Request, res: Response) {
  const file = req.file;
  if (!file) return res.status(400).json({ error: "Missing file" });

  const artifact = await createArtifact({
    analysisId: req.body.analysisId,
    type: req.body.type,
    title: req.body.title,
    mimeType: file.mimetype,
    payload: file.buffer,
    createdBy: String(req.user?.id || req.body.createdBy),
    metadata: req.body.metadata ? JSON.parse(req.body.metadata) : {}
  });

  return res.status(201).json({ artifactId: artifact.id });
}

export async function getArtifacts(req: Request, res: Response) {
  const { analysisId, type } = req.query as { analysisId: string; type?: string };
  const items = await listArtifacts(analysisId, type);
  return res.json({ items });
}

export async function downloadArtifact(req: Request, res: Response) {
  const { artifact, stream } = await getArtifactDownload(req.params.artifactId);
  res.setHeader("Content-Type", artifact.mimeType);
  res.setHeader("Content-Disposition", `inline; filename="${artifact.title}"`);
  return res.send(stream);
}
