import { useState } from "react";
import { saveStoryPoints } from "../services/backlogApi";

type Props = {
  storyId: string;
  value: number | null;
  version: number;
  canEdit: boolean;
  onSaved: (points: number, version: number) => void;
};

export function StoryPointCell({ storyId, value, version, canEdit, onSaved }: Props) {
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState(value?.toString() ?? "");
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState("");

  if (!canEdit) return <span>{value ?? "—"}</span>;

  const validate = (raw: string) => {
    if (raw.trim() === "") return "Story points are required";
    const n = Number(raw);
    if (!Number.isFinite(n) || n < 0) return "Story points must be a non-negative number";
    return "";
  };

  const submit = async () => {
    const v = validate(draft);
    if (v) return setError(v);
    setError("");
    setBusy(true);
    try {
      const parsed = Number(draft);
      const res = await saveStoryPoints({ storyId, points: parsed, version });
      onSaved(res.points, res.version);
      setEditing(false);
    } catch (e: any) {
      setError(e?.message ?? "Failed to save points");
    } finally {
      setBusy(false);
    }
  };

  if (!editing) {
    return (
      <button type="button" onClick={() => setEditing(true)} aria-label="Edit story points">
        {value ?? "—"}
      </button>
    );
  }

  return (
    <div>
      <input
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onKeyDown={(e) => {
          if (e.key === "Enter") submit();
          if (e.key === "Escape") setEditing(false);
        }}
        aria-label="Story points"
      />
      <button type="button" disabled={busy} onClick={submit}>Save</button>
      <button type="button" disabled={busy} onClick={() => setEditing(false)}>Cancel</button>
      {error ? <div role="alert">{error}</div> : null}
    </div>
  );
}
